const t=[{e:"🐍",n:"뱀",cat:"동물",tags:["길몽"],meaning:"뱀은 가장 복합적인 꿈 상징 중 하나예요. 동아시아 전통에서는 재물과 지혜를 상징하며, 융 심리학에서는 변형(Transformation)의 원형이에요.",contexts:[{t:"<strong>뱀이 나를 물었다</strong> → 재물이 들어오는 강한 길조. 황금뱀이면 대길!"},{t:"<strong>뱀이 똬리를 틀고 있다</strong> → 재물이 쌓이고 있다는 뜻. 안정적인 재운"},{t:"<strong>뱀이 허물을 벗는다</strong> → 변화와 재생. 새로운 시작이 다가오고 있어요"},{t:"<strong>뱀이 집 안으로 들어온다</strong> → 가정에 재물복이 들어오는 신호"},{t:"<strong>뱀에게 쫓겨 도망친다</strong> → 피하고 싶은 문제나 사람이 있어요"},{t:"<strong>뱀을 잡았다/죽였다</strong> → 재물을 손에 넣거나 어려움을 극복하는 길몽"},{t:"<strong>뱀이 물속에서 헤엄친다</strong> → 감정과 재물이 함께 흐르는 좋은 기운"},{t:"<strong>큰 뱀이 나타났다</strong> → 크기에 비례해서 재운도 커요. 대형 뱀은 대길"},{t:"<strong>뱀이 말을 걸었다</strong> → 무의식이 중요한 메시지를 전하려는 신호"},{t:"<strong>뱀 여러 마리가 나왔다</strong> → 여러 방면에서 기회가 찾아올 수 있어요"}]},{e:"🐷",n:"돼지",cat:"동물",tags:["길몽","대길"],meaning:"돼지꿈은 한국에서 가장 강력한 길몽. 복권 당첨자 중 돼지꿈을 꾸고 산 사람이 많아요.",contexts:[{t:"<strong>돼지를 잡았다/안았다</strong> → 대길! 재물이 크게 들어올 징조"},{t:"<strong>돼지가 집에 들어온다</strong> → 가정에 재물복이 들어오는 강한 신호"},{t:"<strong>돼지가 새끼를 낳는다</strong> → 재물이 불어나는 대길몽. 풍요의 상징"},{t:"<strong>돼지가 도망간다</strong> → 기회를 놓치거나 재물이 빠져나갈 수 있어요"},{t:"<strong>돼지가 진흙에서 뒹군다</strong> → 풍요 속의 안정. 현재 상태가 좋다는 뜻"},{t:"<strong>금색/황금 돼지</strong> → 최상급 재물 길몽. 로또 사는 사람이 많아요"},{t:"<strong>돼지 여러 마리</strong> → 마리 수만큼 복이 쌓인다는 의미"},{t:"<strong>돼지를 키우는 꿈</strong> → 장기적인 재물 축적. 투자에 좋은 시기"}]},{e:"🐱",n:"고양이",cat:"동물",tags:["중립","주의"],meaning:"고양이는 신비롭고 양면적인 상징. 직감, 독립성, 여성성을 나타내지만 배신이나 경계의 의미도 있어요.",contexts:[{t:"<strong>고양이가 안긴다</strong> → 애정운 상승. 좋아하는 사람과 좋은 일"},{t:"<strong>검은 고양이</strong> → 신중하게 행동해야 할 시기. 주변 경계"},{t:"<strong>고양이가 할퀸다</strong> → 가까운 사람에게 배신당할 수 있으니 주의"},{t:"<strong>고양이 여러 마리</strong> → 주변 사람들의 관심이 집중되는 시기"},{t:"<strong>새끼 고양이</strong> → 작지만 소중한 인연이나 기회가 다가와요"},{t:"<strong>고양이가 울고 있다</strong> → 주변에 도움이 필요한 사람이 있어요"},{t:"<strong>하얀 고양이</strong> → 순수한 사랑이나 좋은 인연의 신호"}]},{e:"🐕",n:"개",cat:"동물",tags:["중립"],meaning:"개는 충성, 우정, 보호를 상징해요. 꿈에서 개의 행동이 현실 관계를 반영하는 경우가 많아요.",contexts:[{t:"<strong>개가 꼬리를 흔든다</strong> → 충실한 친구나 동료의 도움을 받을 수 있어요"},{t:"<strong>개에게 물렸다</strong> → 가까운 사람과의 갈등 주의. 배신 가능성"},{t:"<strong>개가 쫓아온다</strong> → 책임감이나 의무가 당신을 따라다니고 있어요"},{t:"<strong>강아지를 안는다</strong> → 새로운 우정이나 따뜻한 인연"},{t:"<strong>검은 개</strong> → 무의식의 그림자(Shadow). 직면해야 할 감정이 있어요"},{t:"<strong>개가 짖는다</strong> → 위험 경고. 주변 상황을 주의 깊게 살펴보세요"}]},{e:"🐟",n:"물고기",cat:"동물",tags:["길몽"],meaning:"물고기는 재물, 풍요, 다산의 상징. 특히 잉어는 출세와 성공을 의미해요.",contexts:[{t:"<strong>큰 물고기를 잡았다</strong> → 대길! 큰 재물이나 기회를 잡는 꿈"},{t:"<strong>물고기가 뛰어오른다</strong> → 승진, 합격, 성공의 전조"},{t:"<strong>물고기를 먹는다</strong> → 건강운 상승. 영양 보충의 의미도"},{t:"<strong>물고기가 죽어있다</strong> → 기회를 놓쳤거나 에너지가 소진된 상태"},{t:"<strong>금붕어/금색 물고기</strong> → 소원 성취. 작지만 확실한 행운"},{t:"<strong>물고기 떼</strong> → 풍요와 번영. 주변에 좋은 기운이 가득"}]},{e:"🕷️",n:"거미",cat:"동물",tags:["중립"],meaning:"거미는 창조성과 인내, 또는 함정과 두려움의 이중적 상징이에요.",contexts:[{t:"<strong>거미줄을 짠다</strong> → 치밀한 계획이 성공할 거예요. 인내의 보상"},{t:"<strong>거미줄에 걸렸다</strong> → 복잡한 상황이나 관계에 얽매여 있어요"},{t:"<strong>거미가 내려온다</strong> → 재물이 위에서 떨어지는 길조"},{t:"<strong>거미를 죽였다</strong> → 두려움을 극복하는 과정"},{t:"<strong>큰 거미가 나타났다</strong> → 큰 두려움이나 큰 기회 둘 다 가능"}]},{e:"🦅",n:"새/독수리",cat:"동물",tags:["길몽"],meaning:"새는 자유, 메시지, 영혼을 상징해요. 높이 나는 새일수록 더 좋은 길조.",contexts:[{t:"<strong>독수리/매가 하늘을 난다</strong> → 큰 성취와 출세의 전조"},{t:"<strong>새가 어깨에 앉는다</strong> → 귀인의 도움을 받게 돼요"},{t:"<strong>새가 노래한다</strong> → 좋은 소식이 찾아올 징조"},{t:"<strong>새가 죽었다</strong> → 자유가 억압받고 있거나 희망을 잃은 상태"},{t:"<strong>까마귀</strong> → 경고의 메시지. 주의 깊게 주변을 살펴보세요"},{t:"<strong>비둘기</strong> → 평화와 화해. 갈등이 해소될 수 있어요"}]},{e:"💕",n:"전 애인/옛 연인",cat:"사람",tags:["연애운"],meaning:"전 애인 꿈은 단순한 그리움보다 더 깊은 심리적 의미가 있어요. 현재 감정 상태를 반영하는 경우가 많아요.",contexts:[{t:"<strong>전 애인과 다시 사귀는 꿈</strong> → 과거에 대한 미련보다는 현재 외로움의 반영"},{t:"<strong>전 애인이 웃고 있다</strong> → 그 관계에서 좋았던 감정을 그리워하는 상태"},{t:"<strong>전 애인이 울고 있다</strong> → 과거 관계에 대한 죄책감이나 미안함"},{t:"<strong>전 애인이 다른 사람과 함께</strong> → 놓아줘야 할 것을 놓지 못하는 심리"},{t:"<strong>전 애인과 싸운다</strong> → 아직 정리 안 된 감정이 있어요"},{t:"<strong>전 애인이 연락해온다</strong> → 새로운 인연에 대한 기대감의 투영"},{t:"<strong>전 애인과 편하게 대화</strong> → 과거를 수용하고 성장한 상태"},{t:"<strong>전 애인의 결혼 소식</strong> → 비교하는 마음. 자신의 현재에 집중할 때"}]},{e:"👶",n:"아기/아이",cat:"사람",tags:["길몽"],meaning:"아기는 새로운 시작, 순수함, 잠재력을 상징해요. 태몽과 연결되는 경우도 있어요.",contexts:[{t:"<strong>아기를 안는다</strong> → 새로운 시작이나 프로젝트의 성공"},{t:"<strong>아기가 웃는다</strong> → 행복하고 밝은 미래의 전조"},{t:"<strong>아기가 울고 있다</strong> → 돌봐야 할 것을 소홀히 하고 있어요"},{t:"<strong>아기를 낳는다</strong> → 창조적 결실. 오래 준비한 것이 열매 맺어요"},{t:"<strong>아기가 걷는다</strong> → 독립과 성장. 한 단계 도약할 시기"},{t:"<strong>쌍둥이 아기</strong> → 두 배의 기회나 축복"}]},{e:"👨‍👩‍👧",n:"가족",cat:"사람",tags:["중립"],meaning:"가족 꿈은 안정감, 소속감, 또는 가족 관계에 대한 무의식적 감정을 반영해요.",contexts:[{t:"<strong>돌아가신 부모님이 나타났다</strong> → 조언이 필요한 시기. 수호의 의미"},{t:"<strong>돌아가신 분이 밥을 차려준다</strong> → 최고의 길몽. 큰 복이 올 전조"},{t:"<strong>가족과 식사한다</strong> → 화목과 안정. 관계가 좋아지는 신호"},{t:"<strong>가족과 싸운다</strong> → 현실에서 억눌린 갈등이 표출된 것"},{t:"<strong>가족이 아프다</strong> → 역꿈! 오히려 건강해지는 길조"},{t:"<strong>가족이 사라진다</strong> → 독립에 대한 욕구 또는 상실 불안"}]},{e:"🌊",n:"물",cat:"자연",tags:["중립"],meaning:"물은 감정과 무의식의 대표 상징. 물의 상태가 당신의 마음 상태를 직접 반영해요.",contexts:[{t:"<strong>맑고 잔잔한 물</strong> → 마음의 평화. 감정적 안정기"},{t:"<strong>거센 파도/홍수</strong> → 감정이 폭발 직전. 스트레스 과부하"},{t:"<strong>물속에서 헤엄친다</strong> → 감정에 깊이 몰입하거나 탐구하는 상태"},{t:"<strong>물에 빠진다</strong> → 감정에 압도당하는 느낌. 도움이 필요해요"},{t:"<strong>비를 맞는다</strong> → 정화와 새 출발. 시원하면 길조"},{t:"<strong>물 위를 걷는다</strong> → 감정을 통제하고 있다는 자신감의 표현"},{t:"<strong>탁한/더러운 물</strong> → 감정적 혼란이나 건강 주의 신호"},{t:"<strong>폭포를 본다</strong> → 감정의 해방. 억눌렸던 것이 풀리는 시기"}]},{e:"🔥",n:"불",cat:"자연",tags:["길몽","주의"],meaning:"불은 열정, 에너지, 파괴와 재생을 동시에 상징해요. 통제 여부가 해석의 핵심.",contexts:[{t:"<strong>집이 불탄다</strong> → 전통 해몽에서 대길몽! 큰 재물 유입"},{t:"<strong>따뜻한 모닥불</strong> → 안정감과 보호. 좋은 관계의 상징"},{t:"<strong>불을 끈다</strong> → 분노나 갈등을 잘 조절하고 있어요"},{t:"<strong>불에 덴다</strong> → 충동적 행동에 주의. 성급함 경고"},{t:"<strong>불이 꺼진다</strong> → 열정이 사그라들고 있어요. 동기 부여 필요"},{t:"<strong>불꽃놀이</strong> → 축하와 기쁨. 좋은 소식이 올 전조"}]},{e:"🦷",n:"이빨",cat:"신체",tags:["주의"],meaning:"세계 공통 꿈 상징. 자존감, 외모, 노화에 대한 불안과 연결돼요.",contexts:[{t:"<strong>이빨이 하나씩 빠진다</strong> → 지속적인 스트레스. 하나씩 놓아야 할 것"},{t:"<strong>이빨이 한꺼번에 우수수 빠진다</strong> → 큰 변화에 대한 공포"},{t:"<strong>이빨이 부서진다</strong> → 자존감이 흔들리는 시기"},{t:"<strong>이빨이 흔들린다</strong> → 불안정한 상황. 결정을 미루고 있어요"},{t:"<strong>이빨을 뱉는다</strong> → 말하지 못한 것을 내뱉고 싶은 심리"},{t:"<strong>새 이빨이 난다</strong> → 새로운 시작! 성장과 재생의 길조"},{t:"<strong>충치가 생긴다</strong> → 방치하면 커질 문제가 있어요"}]},{e:"💩",n:"똥/배설",cat:"기타",tags:["길몽","대길"],meaning:'동아시아 해몽에서 똥은 최고의 재물 길몽! "돈꿈"이라고도 불려요. 더럽다고 나쁜 게 아니에요.',contexts:[{t:"<strong>똥을 밟았다</strong> → 재물 대길! 예상치 못한 횡재수"},{t:"<strong>똥을 뒤집어썼다</strong> → 초대길몽! 재물이 넘쳐날 정도로 들어와요"},{t:"<strong>똥을 쌌다</strong> → 스트레스 해소와 재물운 동시 상승"},{t:"<strong>화장실이 똥으로 가득하다</strong> → 재물이 가득한 곳. 투자 적기"},{t:"<strong>똥을 치운다</strong> → 문제 해결 후 보상이 따르는 길조"},{t:"<strong>다른 사람 똥을 본다</strong> → 타인의 도움으로 재물이 들어와요"},{t:"<strong>금색 똥</strong> → 최상급 재물 길몽! 말 그대로 금전운 대폭발"},{t:"<strong>똥 냄새가 심하다</strong> → 냄새가 강할수록 재물도 크다는 해석"}]},{e:"🏫",n:"학교/시험",cat:"장소",tags:["주의"],meaning:"졸업 후에도 학교 꿈을 꾸는 건 평가받는 상황에 대한 불안. 세계적으로 가장 흔한 꿈 중 하나예요.",contexts:[{t:"<strong>시험인데 하나도 모른다</strong> → 현실에서 준비 안 된 느낌에 대한 불안"},{t:"<strong>지각한다</strong> → 기회를 놓칠까 봐 두려운 심리"},{t:"<strong>교실을 못 찾겠다</strong> → 자신의 자리/역할에 대한 혼란"},{t:"<strong>발표에서 머리가 하얘진다</strong> → 타인의 시선에 대한 압박감"},{t:"<strong>시험에 합격한다</strong> → 자신감 회복. 곧 좋은 결과가 올 거예요"},{t:"<strong>졸업한다</strong> → 한 단계를 마무리하고 새 시작을 준비하는 시기"}]},{e:"🚗",n:"차/운전",cat:"물건",tags:["중립"],meaning:"차는 인생의 방향과 통제력을 상징해요. 누가 운전하느냐가 핵심 포인트.",contexts:[{t:"<strong>내가 운전한다</strong> → 인생을 잘 컨트롤하고 있어요"},{t:"<strong>다른 사람이 운전한다</strong> → 타인에게 의존하거나 주도권을 뺏긴 느낌"},{t:"<strong>브레이크가 안 먹힌다</strong> → 통제 불능 상황에 대한 불안"},{t:"<strong>교통사고</strong> → 인생 계획에 차질이 생길 수 있다는 경고"},{t:"<strong>새 차를 산다</strong> → 새로운 시작. 좋은 변화의 전조"},{t:"<strong>차가 고장난다</strong> → 건강이나 에너지 관리 필요"},{t:"<strong>고급 차를 탄다</strong> → 지위 상승이나 성공에 대한 욕구"}]},{e:"👗",n:"옷/의상",cat:"물건",tags:["중립"],meaning:"옷은 사회적 이미지, 페르소나(가면)를 상징해요. 어떤 옷을 입었는지가 중요.",contexts:[{t:"<strong>벗은 채로 돌아다닌다</strong> → 비밀이 드러날까 봐 두려운 심리"},{t:"<strong>새 옷을 입는다</strong> → 새로운 이미지, 새 시작"},{t:"<strong>옷이 더럽다</strong> → 평판에 흠이 갈 수 있으니 주의"},{t:"<strong>화려한 옷</strong> → 인정받고 싶은 욕구"},{t:"<strong>교복을 입는다</strong> → 과거의 나로 돌아가고 싶은 향수"},{t:"<strong>옷을 빌려 입는다</strong> → 타인의 역할이나 성격을 모방하려는 시도"}]},{e:"🔑",n:"열쇠/문",cat:"물건",tags:["길몽"],meaning:"열쇠는 기회, 해결책, 비밀의 상징. 문은 새로운 가능성을 의미해요.",contexts:[{t:"<strong>열쇠를 찾았다</strong> → 오래된 문제의 해결책을 발견할 거예요"},{t:"<strong>문이 잠겨있다</strong> → 아직 준비가 안 됐거나 시기가 이른 상태"},{t:"<strong>문이 열렸다</strong> → 새로운 기회가 열리고 있어요"},{t:"<strong>열쇠를 잃어버렸다</strong> → 기회를 놓칠까 봐 불안한 상태"},{t:"<strong>여러 개의 문</strong> → 선택의 기로에 서 있어요"}]},{e:"📱",n:"전화/핸드폰",cat:"물건",tags:["중립"],meaning:"전화는 소통, 연결, 메시지를 상징해요. 현대인의 꿈에 자주 등장.",contexts:[{t:"<strong>전화가 온다</strong> → 소식이나 연락이 올 전조"},{t:"<strong>전화가 안 된다</strong> → 소통 단절에 대한 불안. 외로움의 표현"},{t:"<strong>모르는 번호에서 전화</strong> → 예상치 못한 변화나 소식"},{t:"<strong>전화기가 깨진다</strong> → 관계 단절이나 소통 문제 경고"},{t:"<strong>옛 친구에게 전화한다</strong> → 과거 관계에 대한 그리움"}]},{e:"🏃",n:"쫓기는 꿈",cat:"행동",tags:["흉몽"],meaning:"쫓기는 꿈은 세계에서 가장 흔한 꿈 유형. 회피하고 있는 문제나 감정의 반영이에요.",contexts:[{t:"<strong>낯선 사람에게 쫓긴다</strong> → 정체 모를 불안감. 근원을 찾아야 해요"},{t:"<strong>괴물/좀비에게 쫓긴다</strong> → 두려움이 과장되어 나타난 것"},{t:"<strong>다리가 안 움직인다</strong> → 무력감. 현실에서 해결 못하는 문제"},{t:"<strong>겨우 탈출했다</strong> → 곧 어려움을 극복할 수 있다는 신호"},{t:"<strong>경찰에게 쫓긴다</strong> → 죄책감이나 규칙에 대한 부담"},{t:"<strong>동물에게 쫓긴다</strong> → 본능적 두려움. 감정을 직면해야 할 때"},{t:"<strong>쫓는 대상과 마주본다</strong> → 용기! 두려움을 직면하려는 무의식"}]},{e:"😰",n:"추락/떨어짐",cat:"행동",tags:["흉몽"],meaning:"추락 꿈은 통제력 상실, 불안, 실패 두려움을 반영해요. 잠들기 직전 근육 경련과도 연관.",contexts:[{t:"<strong>높은 곳에서 떨어진다</strong> → 큰 실패에 대한 두려움"},{t:"<strong>엘리베이터가 추락한다</strong> → 급격한 상황 변화에 대한 불안"},{t:"<strong>절벽에서 미끄러진다</strong> → 위태로운 상황을 감지하는 직감"},{t:"<strong>떨어지다 깨어난다</strong> → 입면환각(Hypnic Jerk). 신체적 현상"},{t:"<strong>떨어지다 날아올랐다</strong> → 위기를 기회로 바꿀 수 있는 힘이 있어요"},{t:"<strong>다른 사람이 떨어진다</strong> → 그 사람에 대한 걱정이나 불안"}]},{e:"🍑",n:"태몽/과일",cat:"기타",tags:["태몽","길몽"],meaning:"과일은 풍요와 결실의 상징. 태몽으로 해석되는 경우도 많아요.",contexts:[{t:"<strong>큰 복숭아를 딴다</strong> → 대표적 태몽. 딸 아이일 가능성"},{t:"<strong>사과를 받는다</strong> → 건강하고 총명한 아이의 태몽"},{t:"<strong>포도송이</strong> → 다산이나 풍요. 사업 번창"},{t:"<strong>수박을 자른다</strong> → 큰 결실. 큰 프로젝트의 성공"},{t:"<strong>과일이 썩어있다</strong> → 기회를 놓쳤거나 시기가 지난 상태"},{t:"<strong>과일 나무에 열매가 가득</strong> → 노력의 결실이 풍성하게 맺혀요"}]},{e:"💍",n:"결혼/반지",cat:"기타",tags:["연애운"],meaning:"결혼 꿈은 결합, 헌신, 새로운 파트너십을 상징해요. 반드시 실제 결혼을 의미하진 않아요.",contexts:[{t:"<strong>내가 결혼한다</strong> → 중요한 결정이나 헌신의 시기가 왔어요"},{t:"<strong>결혼식에 초대받는다</strong> → 축하할 일이 생길 거예요"},{t:"<strong>반지를 받는다</strong> → 약속이나 신뢰의 상징. 좋은 인연"},{t:"<strong>반지를 잃어버린다</strong> → 관계에 대한 불안이나 약속 이행 걱정"},{t:"<strong>결혼을 거부한다</strong> → 책임지기 싫은 것이 있어요"}]},{e:"🌧️",n:"비/날씨",cat:"자연",tags:["중립"],meaning:"비는 정화, 슬픔, 새 시작을 동시에 상징해요. 비 온 뒤 맑아지면 특히 좋은 전조.",contexts:[{t:"<strong>비를 맞으며 걷는다</strong> → 정화의 시기. 감정적 리셋"},{t:"<strong>폭우/태풍</strong> → 감정의 폭풍. 큰 변화가 다가오고 있어요"},{t:"<strong>비가 그치고 해가 뜬다</strong> → 힘든 시기가 끝나고 좋아질 징조"},{t:"<strong>우산을 쓴다</strong> → 보호받고 있어요. 누군가가 지켜주고 있어요"},{t:"<strong>눈이 내린다</strong> → 순수함, 새 시작, 차가운 감정의 표현"},{t:"<strong>무지개가 뜬다</strong> → 소원 성취. 희망의 강한 신호"}]},{e:"🪜",n:"계단/엘리베이터",cat:"장소",tags:["중립"],meaning:"계단은 인생의 단계적 변화, 성장을 상징해요. 올라가는지 내려가는지가 핵심.",contexts:[{t:"<strong>계단을 올라간다</strong> → 성장, 승진, 목표 달성을 향해 가고 있어요"},{t:"<strong>계단을 내려간다</strong> → 무의식 탐색이나 퇴보에 대한 불안"},{t:"<strong>끝없는 계단</strong> → 목표에 도달하기 어렵다고 느끼는 상태"},{t:"<strong>계단이 무너진다</strong> → 계획에 차질이 생길 수 있어요"},{t:"<strong>엘리베이터가 빠르게 올라간다</strong> → 급격한 상승. 좋은 변화"}]},{e:"🏖️",n:"바다/해변",cat:"자연",tags:["중립"],meaning:"바다는 무의식의 깊이, 감정의 광대함을 상징해요. 해변은 의식과 무의식의 경계.",contexts:[{t:"<strong>잔잔한 바다</strong> → 마음의 평화. 안정적인 시기"},{t:"<strong>파도가 거세다</strong> → 감정적 동요. 내면의 갈등"},{t:"<strong>바다에서 수영한다</strong> → 무의식을 탐험하는 용기"},{t:"<strong>바다 밑으로 가라앉는다</strong> → 깊은 감정이나 기억에 직면하는 과정"},{t:"<strong>해변을 걷는다</strong> → 의식과 무의식의 균형을 찾는 중"},{t:"<strong>바다에서 보물을 발견한다</strong> → 숨겨진 재능이나 기회를 발견할 거예요"}]},{e:"🎭",n:"유명인/연예인",cat:"사람",tags:["중립"],meaning:"유명인 꿈은 그 사람 자체보다 그 사람이 상징하는 특성을 원하는 심리예요.",contexts:[{t:"<strong>좋아하는 연예인과 대화</strong> → 그 사람의 특성을 내가 갖고 싶은 욕구"},{t:"<strong>유명인이 되었다</strong> → 인정받고 싶은 욕구. 자기 표현에 대한 갈망"},{t:"<strong>유명인과 연애한다</strong> → 이상적인 파트너에 대한 환상"},{t:"<strong>유명인이 도와준다</strong> → 귀인의 도움을 받게 될 수 있어요"}]},{e:"🏥",n:"병원/질병",cat:"장소",tags:["주의"],meaning:"병원 꿈은 치유가 필요한 부분이 있다는 신호예요. 실제 건강보다 심리적 치유인 경우가 많아요.",contexts:[{t:"<strong>병원에 입원한다</strong> → 쉼이 필요해요. 번아웃 경고"},{t:"<strong>수술을 받는다</strong> → 고통스럽지만 필요한 변화의 과정"},{t:"<strong>병이 낫는다</strong> → 회복과 재생. 문제가 해결될 거예요"},{t:"<strong>다른 사람이 아프다</strong> → 그 사람에 대한 걱정이나 관심"},{t:"<strong>주사를 맞는다</strong> → 외부 도움이 필요한 상태"}]},{e:"🎓",n:"졸업/합격",cat:"행동",tags:["길몽"],meaning:"졸업이나 합격 꿈은 성취, 인정, 한 단계 완료를 상징해요.",contexts:[{t:"<strong>졸업장을 받는다</strong> → 오랜 노력의 결실. 인정받는 시기"},{t:"<strong>합격 발표를 본다</strong> → 좋은 소식이 올 거예요"},{t:"<strong>불합격한다</strong> → 역꿈일 가능성. 오히려 좋은 결과"},{t:"<strong>졸업식에 참석한다</strong> → 변화의 시기. 새 시작 준비"}]},{e:"💀",n:"죽음",cat:"사람",tags:["길몽"],meaning:"죽음 꿈은 역설적으로 새로운 시작을 의미해요. 현재의 자아가 죽고 새 자아가 태어나는 변형.",contexts:[{t:"<strong>내가 죽는다</strong> → 현재의 나에서 벗어나 새 출발 예고"},{t:"<strong>가족이 죽는다</strong> → 역꿈! 그 가족에게 오히려 좋은 일이 생겨요"},{t:"<strong>죽은 사람을 본다</strong> → 그리움이나 조언을 원하는 심리"},{t:"<strong>장례식에 참석한다</strong> → 과거를 보내고 새로운 단계로 나아가는 과정"},{t:"<strong>죽었다가 살아난다</strong> → 강력한 재생과 부활의 상징"},{t:"<strong>누군가를 죽인다</strong> → 그 사람이 상징하는 특성을 없애고 싶은 욕구"}]},{e:"💰",n:"돈/재물",cat:"물건",tags:["길몽","대길"],meaning:"돈 꿈은 가치, 자기 가치, 에너지의 교환을 상징해요.",contexts:[{t:"<strong>돈다발을 줍는다</strong> → 예상치 못한 수입이나 행운"},{t:"<strong>돈을 잃는다</strong> → 재물 집착 경고. 낭비 주의"},{t:"<strong>돈을 세고 있다</strong> → 자신의 가치를 평가하는 과정"},{t:"<strong>돈을 받는다</strong> → 노력에 대한 보상이 찾아올 거예요"},{t:"<strong>돈을 준다</strong> → 관계에서 베푸는 역할. 나눔의 기쁨"},{t:"<strong>금/보석을 발견한다</strong> → 숨겨진 재능이나 가치를 발견"}]},{e:"🏠",n:"집",cat:"장소",tags:["중립"],meaning:"집은 자기 자신, 마음의 안식처를 상징해요. 집의 상태가 내면 상태를 보여줘요.",contexts:[{t:"<strong>새집으로 이사한다</strong> → 새로운 시작. 좋은 변화의 전조"},{t:"<strong>집이 무너진다</strong> → 신체적 피로나 심리적 소진 경고"},{t:"<strong>처음 보는 방을 발견한다</strong> → 자신의 새로운 면을 발견하는 과정"},{t:"<strong>옛날 집에 돌아간다</strong> → 과거에 대한 향수. 근원을 찾고 싶은 욕구"},{t:"<strong>집에 물이 새다</strong> → 감정이 새어나가고 있어요. 관리 필요"},{t:"<strong>집을 청소한다</strong> → 내면 정리. 마음의 정화 과정"}]},{e:"🤰",n:"임신",cat:"사람",tags:["길몽","대길"],meaning:"성별 관계없이 새로운 시작, 창조, 잠재력의 실현을 상징해요.",contexts:[{t:"<strong>임신 사실을 알게 된다</strong> → 새 프로젝트나 사업의 시작"},{t:"<strong>아이가 태어난다</strong> → 오랜 노력이 결실을 맺는 시기"},{t:"<strong>배가 크다</strong> → 풍요와 번창. 재물운 상승"},{t:"<strong>아이를 잃는다</strong> → 기회를 놓칠까 봐 불안한 심리"},{t:"<strong>쌍둥이 임신</strong> → 두 배의 축복이나 기회"}]},{e:"🌙",n:"달",cat:"자연",tags:["길몽","중립"],meaning:"달은 무의식, 직관, 감정의 흐름을 상징해요. 달의 모양이 해석의 핵심.",contexts:[{t:"<strong>보름달이 환하다</strong> → 소원 성취. 성공의 예고"},{t:"<strong>달을 따거나 안는다</strong> → 대길몽! 귀인의 도움이나 큰 행운"},{t:"<strong>달이 어둡다</strong> → 감정적 불안. 계획에 변수 가능"},{t:"<strong>초승달</strong> → 새로운 시작의 에너지. 시작하기 좋은 때"},{t:"<strong>달이 떨어진다</strong> → 이상이 무너지는 느낌. 현실 직시 필요"}]},{e:"✈️",n:"여행/출발",cat:"행동",tags:["길몽"],meaning:"여행은 인생의 새로운 여정, 자기 발견을 상징해요.",contexts:[{t:"<strong>즐겁게 여행을 떠난다</strong> → 좋은 변화. 새 만남이나 기회"},{t:"<strong>짐을 잃거나 놓친다</strong> → 중요한 것을 놓치지 않도록 점검 필요"},{t:"<strong>비행기를 타고 오른다</strong> → 지위나 상황이 크게 상승하는 길몽"},{t:"<strong>여행지에서 길을 잃는다</strong> → 인생의 방향에 대한 혼란"},{t:"<strong>배를 타고 떠난다</strong> → 감정의 여행. 새로운 감정 경험"}]},{e:"🌸",n:"꽃",cat:"자연",tags:["길몽"],meaning:"꽃은 아름다움, 일시성, 성장의 결실을 상징해요.",contexts:[{t:"<strong>꽃이 활짝 피었다</strong> → 노력이 열매 맺는 시기. 사랑운도 상승"},{t:"<strong>꽃을 받는다</strong> → 사랑이나 감사를 받게 될 거예요"},{t:"<strong>꽃이 시든다</strong> → 아름다운 시기가 지나가고 있어요"},{t:"<strong>꽃밭을 걷는다</strong> → 행복하고 평화로운 시기"},{t:"<strong>벚꽃이 흩날린다</strong> → 아름답지만 일시적인 것에 대한 감상"}]},{e:"🐉",n:"용",cat:"동물",tags:["길몽","대길"],meaning:"용은 동아시아 최고의 길몽 상징. 권력, 성공, 수호를 의미해요. 태몽으로도 최고급.",contexts:[{t:"<strong>용이 하늘을 난다</strong> → 대길! 큰 성취와 출세의 전조"},{t:"<strong>용이 내 앞에 나타났다</strong> → 강력한 수호와 행운의 에너지"},{t:"<strong>금색 용</strong> → 최상급 길몽. 인생을 바꿀 큰 기회"},{t:"<strong>용이 여의주를 물고 있다</strong> → 소원 성취. 원하는 것을 얻을 거예요"},{t:"<strong>용을 타고 하늘로 올라간다</strong> → 극적인 성공이나 상승"},{t:"<strong>용이 물에서 올라온다</strong> → 잠재력이 폭발하는 시기"}]},{e:"🐄",n:"소",cat:"동물",tags:["길몽"],meaning:"소는 근면, 재물, 풍요의 상징. 농경 사회에서 가장 중요한 자산이었어요.",contexts:[{t:"<strong>소가 집에 들어온다</strong> → 재물이 들어오는 길조"},{t:"<strong>소를 타고 간다</strong> → 순조로운 진행. 목표를 향해 잘 가고 있어요"},{t:"<strong>소가 울다</strong> → 주변 사람의 도움 요청. 관심 기울이세요"},{t:"<strong>황소</strong> → 강한 재물운과 에너지"},{t:"<strong>송아지를 낳는다</strong> → 재물 증식. 투자 결실"}]},{e:"🐎",n:"말",cat:"동물",tags:["길몽"],meaning:"말은 자유, 열정, 추진력의 상징. 백마는 특히 강한 길몽.",contexts:[{t:"<strong>말을 타고 달린다</strong> → 목표를 향한 강한 추진력. 성공 예고"},{t:"<strong>백마가 나타났다</strong> → 귀인의 등장. 큰 행운"},{t:"<strong>말이 도망간다</strong> → 기회를 놓칠 수 있으니 잡아야 해요"},{t:"<strong>말에서 떨어진다</strong> → 자만 경계. 겸손이 필요한 시기"},{t:"<strong>말 떼가 달린다</strong> → 에너지 폭발. 활력 넘치는 시기"}]},{e:"🐢",n:"거북이",cat:"동물",tags:["길몽","대길"],meaning:"거북이는 장수, 안정, 인내의 상징. 등에 올라타면 더 큰 길조.",contexts:[{t:"<strong>거북이를 본다</strong> → 장수와 건강. 느리지만 확실한 성공"},{t:"<strong>거북이 등에 올라탄다</strong> → 대길! 큰 행운이 찾아와요"},{t:"<strong>거북이가 바다로 간다</strong> → 소원이 이뤄지는 과정"},{t:"<strong>금색 거북이</strong> → 재물과 장수 동시에. 최상급 길몽"}]},{e:"🐸",n:"개구리",cat:"동물",tags:["길몽"],meaning:"개구리는 변신과 풍요의 상징. 올챙이에서 변하듯 변화의 메시지.",contexts:[{t:"<strong>개구리가 뛰어다닌다</strong> → 재물이 들어오는 길조"},{t:"<strong>개구리가 울다</strong> → 좋은 소식이 올 전조"},{t:"<strong>개구리를 잡는다</strong> → 작지만 확실한 행운을 잡아요"},{t:"<strong>금개구리</strong> → 재물 대길몽"}]},{e:"🦁",n:"호랑이/사자",cat:"동물",tags:["길몽","대길"],meaning:"호랑이는 한국 전통에서 산신의 사자. 용맹, 권력, 수호의 상징.",contexts:[{t:"<strong>호랑이가 나타났다</strong> → 강한 수호 에너지. 어려움을 이겨낼 힘"},{t:"<strong>호랑이를 탄다</strong> → 권력과 성공을 손에 넣을 길조"},{t:"<strong>호랑이에게 쫓긴다</strong> → 강한 사람이나 상황에 대한 두려움"},{t:"<strong>호랑이가 집에 들어온다</strong> → 큰 인물이 탄생할 태몽 또는 대길"},{t:"<strong>백호</strong> → 최상급 길몽. 신성한 존재의 보호"},{t:"<strong>호랑이 새끼</strong> → 재능 있는 아이의 태몽. 잠재력"}]},{e:"🐘",n:"코끼리",cat:"동물",tags:["길몽"],meaning:"코끼리는 지혜, 힘, 기억을 상징해요. 크기만큼 큰 행운.",contexts:[{t:"<strong>코끼리를 탄다</strong> → 높은 지위와 부. 리더십"},{t:"<strong>코끼리가 다가온다</strong> → 큰 기회가 찾아오고 있어요"},{t:"<strong>코끼리 떼</strong> → 대규모 행운. 사업 확장"},{t:"<strong>아기 코끼리</strong> → 귀여운 행운의 시작"}]},{e:"🐜",n:"개미/벌레",cat:"동물",tags:["중립"],meaning:"작은 곤충은 근면, 사소한 걱정, 또는 집요함을 상징해요.",contexts:[{t:"<strong>개미 떼가 이동한다</strong> → 근면한 노력이 성과를 낼 거예요"},{t:"<strong>벌레가 몸에 붙는다</strong> → 사소하지만 신경 쓰이는 문제"},{t:"<strong>나비가 날아온다</strong> → 변신과 아름다움. 좋은 변화"},{t:"<strong>벌에 쏘인다</strong> → 경고. 주변의 날카로운 말에 주의"},{t:"<strong>반딧불이</strong> → 어둠 속 희망. 작지만 확실한 빛"}]},{e:"🍚",n:"밥/음식",cat:"음식",tags:["길몽"],meaning:"음식은 에너지, 풍요, 사랑을 상징해요. 맛있게 먹으면 길조.",contexts:[{t:"<strong>밥을 먹는다</strong> → 기본적 욕구 충족. 안정적인 시기"},{t:"<strong>맛있는 음식이 가득하다</strong> → 풍요와 행운. 좋은 시기"},{t:"<strong>음식이 썩어있다</strong> → 기회가 지났거나 건강 주의"},{t:"<strong>음식을 만든다</strong> → 창조적 에너지. 새로운 것을 준비 중"},{t:"<strong>다른 사람에게 음식을 준다</strong> → 나눔과 사랑. 좋은 관계"},{t:"<strong>고기를 먹는다</strong> → 에너지 충전. 재물운 상승"}]},{e:"🍰",n:"떡/과자",cat:"음식",tags:["길몽"],meaning:"떡은 한국 전통에서 복과 경사의 상징. 떡을 나누면 복도 나눠져요.",contexts:[{t:"<strong>떡을 받는다</strong> → 경사스러운 일이 생길 거예요"},{t:"<strong>떡을 나눠준다</strong> → 좋은 일을 나누면 복이 배가 돼요"},{t:"<strong>떡이 크고 탐스럽다</strong> → 큰 경사. 승진이나 합격"},{t:"<strong>송편을 빚는다</strong> → 소원을 담는 과정. 곧 이뤄질 거예요"}]},{e:"🍺",n:"술",cat:"음식",tags:["중립"],meaning:"술은 해방, 사교, 억압된 감정의 표출을 상징해요.",contexts:[{t:"<strong>즐겁게 술을 마신다</strong> → 스트레스 해소. 좋은 인간관계"},{t:"<strong>술에 취한다</strong> → 현실에서 벗어나고 싶은 욕구"},{t:"<strong>술을 거절한다</strong> → 자제력. 유혹을 잘 이겨내고 있어요"},{t:"<strong>술잔을 깨뜨린다</strong> → 관계의 변화. 새로운 시작"}]},{e:"🏊",n:"수영/잠수",cat:"행동",tags:["중립"],meaning:"수영은 감정 속을 헤쳐나가는 과정. 잘 헤엄치면 감정 조절이 잘 되고 있다는 뜻.",contexts:[{t:"<strong>자유롭게 수영한다</strong> → 감정을 잘 다루고 있어요"},{t:"<strong>물속에서 숨을 쉰다</strong> → 무의식과 조화를 이루는 상태"},{t:"<strong>허우적거린다</strong> → 감정에 압도당하고 있어요. 도움 필요"},{t:"<strong>깊이 잠수한다</strong> → 자기 내면을 깊이 탐구하는 과정"}]},{e:"💃",n:"춤/노래",cat:"행동",tags:["길몽"],meaning:"춤과 노래는 기쁨, 자기 표현, 해방의 상징.",contexts:[{t:"<strong>즐겁게 춤을 춘다</strong> → 자유롭고 행복한 시기. 자기 표현"},{t:"<strong>무대에서 공연한다</strong> → 주목받고 싶은 욕구. 인정받을 기회"},{t:"<strong>노래를 부른다</strong> → 감정 표현. 마음속 이야기를 전하고 싶어요"},{t:"<strong>춤을 못 추겠다</strong> → 사회적 상황에서의 불안감"}]},{e:"✈️",n:"날아다니기",cat:"행동",tags:["길몽"],meaning:"비행은 자유, 초월, 한계 극복의 강력한 상징.",contexts:[{t:"<strong>자유롭게 날아다닌다</strong> → 해방감. 목표를 향한 자신감"},{t:"<strong>날개를 펼친다</strong> → 잠재력이 발현되는 시기"},{t:"<strong>날다가 떨어진다</strong> → 과대평가에 대한 경고. 현실 점검"},{t:"<strong>다른 사람과 함께 날다</strong> → 협력과 공유. 함께하는 성장"}]},{e:"🤜",n:"싸움/갈등",cat:"행동",tags:["주의"],meaning:"싸움은 내면의 갈등이나 현실 스트레스의 표출.",contexts:[{t:"<strong>모르는 사람과 싸운다</strong> → 자기 자신의 다른 면과 갈등 중"},{t:"<strong>가족/친구와 싸운다</strong> → 현실에서 억눌린 감정이 표출"},{t:"<strong>싸움에서 이긴다</strong> → 어려움을 극복할 힘이 있어요"},{t:"<strong>싸움에서 진다</strong> → 좌절감. 하지만 배움의 기회"},{t:"<strong>싸움을 말린다</strong> → 중재자 역할. 균형을 찾으려는 노력"}]},{e:"👼",n:"천사/신",cat:"초자연",tags:["길몽"],meaning:"신성한 존재는 보호, 계시, 영적 성장의 상징.",contexts:[{t:"<strong>천사가 나타났다</strong> → 보호받고 있어요. 안심해도 돼요"},{t:"<strong>신의 목소리를 듣는다</strong> → 중요한 직감이나 깨달음의 순간"},{t:"<strong>빛이 내려온다</strong> → 축복과 은총. 좋은 기운이 가득"},{t:"<strong>절/교회/사찰에 간다</strong> → 영적 평화를 구하는 마음. 마음의 안식"}]},{e:"👻",n:"귀신/유령",cat:"초자연",tags:["흉몽"],meaning:"귀신은 직면하지 못한 감정, 과거의 미련, 억압된 기억의 투영.",contexts:[{t:"<strong>귀신이 서 있다</strong> → 직면해야 할 감정이 있어요"},{t:"<strong>귀신에게 쫓긴다</strong> → 과거의 트라우마가 따라다니고 있어요"},{t:"<strong>귀신과 대화한다</strong> → 과거와의 화해. 치유의 과정"},{t:"<strong>귀신이 웃는다</strong> → 의외로 수호의 의미. 보호받고 있어요"},{t:"<strong>가위눌린다</strong> → 수면 무호흡 가능성. 수면 환경 점검"},{t:"<strong>돌아가신 분이 밥을 차려준다</strong> → 최고 길몽! 큰 복의 전조"},{t:"<strong>돌아가신 분이 손짓한다</strong> → 건강 주의. 쉼이 필요해요"}]},{e:"🔴",n:"색깔",cat:"기타",tags:["중립"],meaning:"꿈 속 색깔은 감정 상태를 직접 반영하는 중요한 단서.",contexts:[{t:"<strong>빨간색이 강하다</strong> → 열정, 분노, 사랑 — 강렬한 감정의 시기"},{t:"<strong>파란색/푸른색</strong> → 평화, 우울, 신뢰 — 감정의 깊이"},{t:"<strong>금색/노란색</strong> → 재물, 행운, 지혜 — 길조"},{t:"<strong>검은색</strong> → 무의식, 두려움, 미지의 것"},{t:"<strong>하얀색</strong> → 순수, 새 시작, 정화"},{t:"<strong>보라색</strong> → 영성, 직관, 치유의 에너지"},{t:"<strong>초록색</strong> → 성장, 치유, 자연과의 연결"}]},{e:"🔢",n:"숫자",cat:"기타",tags:["중립"],meaning:"꿈에 나타난 숫자는 중요한 메시지를 담고 있을 수 있어요.",contexts:[{t:"<strong>3</strong> → 완성과 조화. 삼위일체. 균형 잡힌 상태"},{t:"<strong>7</strong> → 행운과 영성. 직관이 강해지는 시기"},{t:"<strong>반복되는 숫자 (111, 222)</strong> → 우주의 메시지. 주의를 기울이세요"},{t:"<strong>큰 숫자</strong> → 풍요나 과부하. 맥락에 따라 달라요"},{t:"<strong>0</strong> → 무한의 가능성. 새로운 시작점"}]},{e:"🏔️",n:"산",cat:"자연",tags:["길몽"],meaning:"산은 목표, 도전, 성취를 상징해요. 정상에 오르면 대길.",contexts:[{t:"<strong>산 정상에 올랐다</strong> → 목표 달성! 큰 성취의 전조"},{t:"<strong>산을 오르는 중이다</strong> → 힘들지만 올바른 방향으로 가고 있어요"},{t:"<strong>산에서 내려온다</strong> → 한 단계 완료. 다음을 준비하는 시기"},{t:"<strong>산이 무너진다</strong> → 큰 변화나 충격. 하지만 재건 가능"},{t:"<strong>산에서 호랑이를 만난다</strong> → 대길! 권력자의 도움"}]},{e:"🌉",n:"다리",cat:"장소",tags:["중립"],meaning:"다리는 전환점, 연결, 결정의 순간을 상징해요.",contexts:[{t:"<strong>다리를 건넌다</strong> → 결정을 내렸어요. 새 단계로의 전환"},{t:"<strong>다리가 끊어졌다</strong> → 연결이 단절될 위험. 관계 점검"},{t:"<strong>다리 위에 서 있다</strong> → 결정의 기로. 어느 쪽으로 갈지 고민 중"},{t:"<strong>아름다운 다리</strong> → 좋은 기회가 연결되고 있어요"}]},{e:"🚪",n:"문/출입구",cat:"장소",tags:["중립"],meaning:"문은 새로운 가능성, 비밀, 전환을 상징해요.",contexts:[{t:"<strong>문을 연다</strong> → 새로운 기회가 열리고 있어요"},{t:"<strong>문이 잠겨있다</strong> → 아직 준비가 안 됐어요. 시기를 기다리세요"},{t:"<strong>여러 개의 문</strong> → 선택의 기로. 직감을 믿으세요"},{t:"<strong>문 뒤에 뭔가 있다</strong> → 궁금증과 기대. 탐구하려는 욕구"}]},{e:"👁️",n:"눈/시력",cat:"신체",tags:["중립"],meaning:"눈은 인식, 통찰, 진실을 보는 능력을 상징해요.",contexts:[{t:"<strong>시야가 흐리다</strong> → 상황 판단이 어려운 시기. 신중해야 해요"},{t:"<strong>제3의 눈이 열린다</strong> → 직관력 폭발. 영적 성장"},{t:"<strong>눈이 밝아진다</strong> → 진실을 깨닫게 되는 순간"},{t:"<strong>눈물을 흘린다</strong> → 감정 해방. 정화의 과정"}]},{e:"✋",n:"손/발",cat:"신체",tags:["중립"],meaning:"손은 행동력과 관계를, 발은 기반과 진행 방향을 상징해요.",contexts:[{t:"<strong>손을 잡는다</strong> → 유대감, 약속, 연결"},{t:"<strong>손에 뭔가 쥐고 있다</strong> → 기회나 재물을 잡고 있어요"},{t:"<strong>발이 안 움직인다</strong> → 현실에서 진전이 없다고 느끼는 상태"},{t:"<strong>맨발로 걷는다</strong> → 자연과 연결. 있는 그대로의 자신"},{t:"<strong>손이 커진다</strong> → 능력과 영향력이 커지고 있어요"}]},{e:"💇",n:"머리카락",cat:"신체",tags:["중립"],meaning:"머리카락은 생각, 정체성, 매력을 상징해요.",contexts:[{t:"<strong>머리카락이 빠진다</strong> → 스트레스나 자신감 저하"},{t:"<strong>머리를 자른다</strong> → 변화를 원해요. 과거 정리"},{t:"<strong>머리가 길어진다</strong> → 매력이나 영향력이 커지고 있어요"},{t:"<strong>머리 색이 변한다</strong> → 정체성의 변화. 새로운 나"},{t:"<strong>하얀 머리카락</strong> → 지혜의 상징이지만 노화 불안도 반영"}]},{e:"🔪",n:"살인/폭력",cat:"흉몽",tags:["흉몽"],meaning:"폭력적인 꿈은 분노, 억압된 감정, 변화에 대한 강렬한 욕구를 반영해요. 실제 폭력 성향과는 무관합니다.",contexts:[{t:"<strong>누군가에게 공격당한다</strong> → 현실에서 위협받고 있다고 느끼는 상태"},{t:"<strong>내가 누군가를 해친다</strong> → 그 사람이 상징하는 것을 제거하고 싶은 욕구"},{t:'<strong>칼이나 무기를 본다</strong> → 결단이 필요한 시기. 칼은 "자르는" 결정의 상징'},{t:"<strong>피를 본다</strong> → 에너지 소진이나 감정적 상처. 쉼이 필요해요"},{t:"<strong>전쟁터에 있다</strong> → 내면의 극심한 갈등. 여러 가치관이 충돌 중"},{t:"<strong>총소리를 듣는다</strong> → 갑작스러운 변화에 대한 경고"}]},{e:"🕸️",n:"갇힘/감금",cat:"흉몽",tags:["흉몽"],meaning:"갇히는 꿈은 자유 억압, 선택의 제한, 통제당하는 느낌을 반영해요.",contexts:[{t:"<strong>방에 갇혔다</strong> → 현실에서 벗어나고 싶지만 못하는 상황"},{t:"<strong>감옥에 있다</strong> → 죄책감이나 자기 처벌의 심리"},{t:"<strong>출구를 찾지 못한다</strong> → 해결책을 모르겠다는 무력감"},{t:"<strong>미로에 갇혔다</strong> → 복잡한 상황에서 방향을 잃은 상태"},{t:"<strong>갇혔다가 탈출했다</strong> → 곧 어려움에서 벗어날 수 있다는 신호"},{t:"<strong>지하실에 있다</strong> → 무의식 깊은 곳의 억압된 기억"}]},{e:"🌑",n:"어둠/공포",cat:"흉몽",tags:["흉몽"],meaning:"어둠은 미지에 대한 두려움, 불확실성, 또는 무의식의 그림자를 상징해요.",contexts:[{t:"<strong>칠흑 같은 어둠에 있다</strong> → 앞이 안 보이는 불안. 방향을 잃은 느낌"},{t:"<strong>무언가가 다가오는 느낌</strong> → 정체 모를 위협. 근원을 찾아야 해요"},{t:"<strong>소리만 들리고 안 보인다</strong> → 직감은 감지하지만 확인 못하는 불안"},{t:"<strong>어둠 속에서 빛을 발견</strong> → 희망의 신호! 곧 출구를 찾을 거예요"},{t:"<strong>밤길을 혼자 걷는다</strong> → 고독감이나 외로움의 반영"}]},{e:"🏚️",n:"폐허/파괴",cat:"흉몽",tags:["흉몽"],meaning:"파괴된 공간은 상실, 변화, 무너진 계획을 상징해요. 하지만 폐허 위에 새것이 세워져요.",contexts:[{t:"<strong>건물이 무너진다</strong> → 신뢰하던 것이 흔들리는 상황"},{t:"<strong>폐허를 걷는다</strong> → 과거의 상처를 되돌아보는 과정"},{t:"<strong>지진이 난다</strong> → 삶의 기반이 흔들리는 큰 변화"},{t:"<strong>화재 후 잿더미</strong> → 전통 해몽에서는 재건과 재물의 길조!"},{t:"<strong>태풍에 휩쓸린다</strong> → 통제 불능의 감정. 폭풍 후 고요가 올 거예요"}]},{e:"😱",n:"악몽/공황",cat:"흉몽",tags:["흉몽"],meaning:"반복되는 악몽은 무의식이 강하게 신호를 보내는 것. 해결 안 된 감정이 있어요.",contexts:[{t:"<strong>소리를 지르는데 안 나온다</strong> → 표현하지 못한 감정이 쌓여 있어요"},{t:"<strong>도움을 요청하지만 아무도 없다</strong> → 현실에서 외로움이나 고립감"},{t:"<strong>같은 악몽이 반복된다</strong> → 핵심 메시지를 놓치고 있어요. 직면이 필요"},{t:"<strong>꿈인 줄 알면서 깨어나지 못한다</strong> → 현실과 이상의 괴리감"},{t:"<strong>깨어났는데 또 꿈이다 (꿈속의 꿈)</strong> → 현실 도피 욕구. 여러 층의 불안"},{t:"<strong>잠에서 깨려고 발버둥친다</strong> → 통제력을 되찾고 싶은 강한 욕구"}]},{e:"🤢",n:"구토/질병",cat:"흉몽",tags:["흉몽","주의"],meaning:'신체 이상 꿈은 실제 건강 문제보다 감정적/심리적 "소화 불량"을 반영하는 경우가 많아요.',contexts:[{t:"<strong>구토한다</strong> → 받아들이기 힘든 것을 거부하는 심리"},{t:"<strong>심하게 아프다</strong> → 정서적 소진. 쉼이 절실해요"},{t:"<strong>병원에 실려간다</strong> → 주변 도움이 필요한 상태"},{t:"<strong>몸이 마비된다</strong> → 무력감. 행동하지 못하는 좌절"},{t:"<strong>상처에서 피가 난다</strong> → 감정적 상처가 치유되지 않은 상태"}]},{e:"🌊",n:"익사/물에 빠짐",cat:"흉몽",tags:["흉몽"],meaning:"물에 빠지는 꿈은 감정에 압도당하는 공포. 현실에서 벅찬 상황을 반영해요.",contexts:[{t:"<strong>물에 빠져서 허우적거린다</strong> → 감당 안 되는 상황에 처해 있어요"},{t:"<strong>누군가 물에 빠진다</strong> → 그 사람에 대한 걱정이나 구원 욕구"},{t:"<strong>물속으로 가라앉는다</strong> → 우울감이나 무기력의 반영"},{t:"<strong>물에서 구조된다</strong> → 도움이 올 거예요. 희망의 신호"},{t:"<strong>탁한 물에 빠진다</strong> → 복잡한 감정이나 상황에 휘말린 상태"}]},{e:"🔥",n:"화상/불에 타다",cat:"흉몽",tags:["흉몽","주의"],meaning:"불에 타는 꿈은 분노, 질투, 또는 파괴적 변화를 상징해요. 하지만 전통적으로 재물 길조이기도.",contexts:[{t:"<strong>불에 덴다</strong> → 성급한 행동 경고. 감정 조절 필요"},{t:"<strong>온몸에 불이 붙는다</strong> → 극단적 감정 상태. 분노 폭발 직전"},{t:"<strong>불길에 갇힌다</strong> → 위기 상황이지만 탈출 가능"},{t:"<strong>다른 사람이 불에 타다</strong> → 그 사람과의 관계에서 갈등 경고"}]},{e:"🐍",n:"뱀에게 쫓기다",cat:"흉몽",tags:["흉몽"],meaning:"뱀이 길몽 상징이지만, 쫓기거나 공격받으면 두려움과 회피의 의미가 돼요.",contexts:[{t:"<strong>뱀에게 쫓긴다</strong> → 피하고 싶은 사람이나 상황이 있어요"},{t:"<strong>뱀에게 물렸는데 아프다</strong> → 가까운 사람에게 상처받을 수 있어요"},{t:"<strong>독사가 나타났다</strong> → 주변에 악의적인 사람이나 위험 요소"},{t:"<strong>뱀이 목을 감는다</strong> → 압박감이나 숨 막히는 관계"},{t:"<strong>뱀 떼에 둘러싸인다</strong> → 사방에서 오는 스트레스"}]},{e:"💔",n:"이별/상실",cat:"흉몽",tags:["흉몽","연애운"],meaning:"이별 꿈은 관계에 대한 불안이나 자기 가치에 대한 의문을 반영해요.",contexts:[{t:"<strong>연인이 떠나간다</strong> → 관계에 대한 불안감. 역꿈일 가능성도"},{t:"<strong>이별 통보를 받는다</strong> → 거절에 대한 두려움"},{t:"<strong>연인이 바람핀다</strong> → 신뢰 문제이지 실제 사건의 예고가 아니에요"},{t:"<strong>소중한 것을 잃어버린다</strong> → 상실 불안. 지금 가진 것에 감사할 때"},{t:"<strong>장례식에 참석한다</strong> → 과거를 보내고 새 단계로 나아가는 과정"},{t:"<strong>울면서 깨어난다</strong> → 감정 정화 중. 억눌린 슬픔이 풀리는 과정"}]},{e:"🏃‍♂️",n:"도망/탈출",cat:"흉몽",tags:["흉몽"],meaning:"도망치는 꿈은 현실에서 피하고 있는 문제의 직접적 반영.",contexts:[{t:"<strong>뛰어도 제자리다</strong> → 노력해도 진전이 없다는 좌절감"},{t:"<strong>숨을 곳이 없다</strong> → 피할 수 없는 현실. 직면이 필요"},{t:"<strong>누군가를 데리고 도망친다</strong> → 보호 본능. 책임감의 무게"},{t:"<strong>막다른 길에 몰린다</strong> → 선택지가 없다고 느끼는 상태"},{t:"<strong>도망치다 숨는 데 성공한다</strong> → 일시적 안도이지만 근본 해결 필요"}]},{e:"🦷",n:"신체 변형",cat:"흉몽",tags:["흉몽"],meaning:"몸이 변하는 꿈은 정체성 불안, 자기 이미지에 대한 걱정.",contexts:[{t:'<strong>얼굴이 변한다</strong> → 정체성의 위기. "나는 누구인가"'},{t:"<strong>몸이 줄어든다</strong> → 자신감 하락. 존재감이 작아지는 느낌"},{t:"<strong>몸이 커진다</strong> → 책임감이나 영향력이 커지는 부담"},{t:"<strong>늙어버린다</strong> → 시간에 대한 불안. 기회를 놓칠까 봐 조급"},{t:"<strong>다른 사람으로 변한다</strong> → 그 사람의 특성을 원하거나 두려워하는 심리"}]},{e:"🍜",n:"국/라면",cat:"음식",tags:["중립"],meaning:"뜨거운 국물 음식은 위로, 치유, 가정의 따뜻함을 상징해요.",contexts:[{t:"<strong>뜨거운 국을 먹는다</strong> → 몸과 마음이 치유되는 과정"},{t:"<strong>국이 식어있다</strong> → 관계나 열정이 식고 있어요"},{t:"<strong>라면을 끓인다</strong> → 빠른 해결을 원하는 마음. 급한 상황"},{t:"<strong>국을 쏟는다</strong> → 감정이 넘쳐서 통제하기 어려운 상태"}]},{e:"🍎",n:"과일/채소",cat:"음식",tags:["길몽"],meaning:"신선한 과일은 건강, 풍요, 열매의 상징. 종류에 따라 의미가 달라요.",contexts:[{t:"<strong>사과를 먹는다</strong> → 건강운 상승. 지식을 얻게 되는 신호"},{t:"<strong>포도를 먹는다</strong> → 풍요와 다산. 여러 기회가 한꺼번에"},{t:"<strong>바나나</strong> → 가벼운 행운. 소소한 좋은 일"},{t:"<strong>썩은 과일</strong> → 기회를 놓쳤어요. 시기를 재점검"},{t:"<strong>감을 따다</strong> → 노력의 결실. 때가 무르익었어요"},{t:"<strong>수박을 자르다</strong> → 큰 프로젝트의 성과를 나눠갖는 시기"}]},{e:"🍖",n:"고기/생선",cat:"음식",tags:["길몽"],meaning:"고기는 에너지, 힘, 물질적 풍요를 상징해요.",contexts:[{t:"<strong>고기를 구워 먹는다</strong> → 재물운 상승. 에너지 충전"},{t:"<strong>회를 먹는다</strong> → 날것 그대로의 진실을 마주하는 시기"},{t:"<strong>뼈만 남은 고기</strong> → 이미 기회가 지나갔을 수 있어요"},{t:"<strong>고기를 나눠준다</strong> → 나눔의 복. 베풀면 돌아와요"}]},{e:"🍞",n:"빵/케이크",cat:"음식",tags:["길몽"],meaning:"빵은 기본적 풍요와 나눔, 케이크는 축하와 기쁨의 상징.",contexts:[{t:"<strong>빵을 굽는다</strong> → 무언가를 정성스럽게 준비하는 과정"},{t:"<strong>케이크를 먹는다</strong> → 축하할 일이 생겨요! 기쁜 소식"},{t:"<strong>빵이 곰팡이 피었다</strong> → 방치한 것이 문제가 될 수 있어요"},{t:"<strong>생일 케이크</strong> → 새로운 한 해의 시작. 축복"}]},{e:"☕",n:"커피/차",cat:"음식",tags:["중립"],meaning:"커피와 차는 각성, 사교, 여유의 상징.",contexts:[{t:"<strong>커피를 마신다</strong> → 정신 차릴 일이 있어요. 깨어나야 할 때"},{t:"<strong>차를 마신다</strong> → 마음의 여유. 평화로운 시기"},{t:"<strong>커피를 쏟는다</strong> → 각성의 기회를 놓칠 수 있어요"},{t:"<strong>누군가와 차를 마신다</strong> → 좋은 대화나 인연이 찾아올 징조"}]},{e:"🔮",n:"점/타로",cat:"초자연",tags:["중립"],meaning:"점이나 타로 꿈은 미래에 대한 불안이나 답을 찾으려는 욕구.",contexts:[{t:"<strong>점을 보러 간다</strong> → 현실에서 방향을 잃었다고 느끼는 상태"},{t:"<strong>좋은 점괘가 나온다</strong> → 직감을 믿어도 좋아요"},{t:"<strong>나쁜 점괘</strong> → 걱정이 과도한 상태. 불안의 투영"},{t:"<strong>타로 카드를 뽑는다</strong> → 선택의 기로. 직감이 답을 알고 있어요"}]},{e:"🧙",n:"마법/초능력",cat:"초자연",tags:["길몽"],meaning:"마법은 무한한 가능성, 숨겨진 재능, 현실 초월의 상징.",contexts:[{t:"<strong>마법을 쓸 수 있다</strong> → 자신의 잠재력을 깨달아가는 과정"},{t:"<strong>투명인간이 된다</strong> → 인정받지 못한다는 느낌. 존재감 갈망"},{t:"<strong>시간을 멈춘다</strong> → 쉼이 필요해요. 현실의 속도가 벅찬 상태"},{t:"<strong>순간이동한다</strong> → 빠른 변화를 원하는 마음"},{t:"<strong>불을 다루는 능력</strong> → 열정과 분노를 통제하는 힘"}]},{e:"👽",n:"외계인/UFO",cat:"초자연",tags:["중립"],meaning:"외계인은 낯선 것, 미지의 경험, 소외감을 상징해요.",contexts:[{t:"<strong>외계인을 만난다</strong> → 완전히 새로운 경험이 다가오고 있어요"},{t:"<strong>UFO를 본다</strong> → 관점의 전환. 높은 곳에서 바라볼 필요"},{t:"<strong>외계인에게 납치된다</strong> → 통제 불능의 변화에 대한 두려움"},{t:"<strong>외계인과 소통한다</strong> → 다른 문화나 사고방식을 수용하는 과정"}]},{e:"🧟",n:"좀비/괴물",cat:"초자연",tags:["흉몽"],meaning:"좀비는 무의미한 반복, 에너지 고갈, 감정 없는 상태를 상징해요.",contexts:[{t:"<strong>좀비에게 쫓긴다</strong> → 감정 없는 일상에서 벗어나고 싶은 마음"},{t:"<strong>좀비가 된다</strong> → 번아웃. 기계적으로 살고 있다는 경고"},{t:"<strong>괴물과 싸운다</strong> → 내면의 두려움과 맞서는 용기"},{t:"<strong>괴물이 사라진다</strong> → 두려움을 극복하는 과정이 끝나가요"}]},{e:"🌟",n:"별/우주",cat:"초자연",tags:["길몽"],meaning:"별은 희망, 목표, 영적 성장을 상징해요.",contexts:[{t:"<strong>별을 세고 있다</strong> → 소원이 많아요. 우선순위를 정할 때"},{t:"<strong>별이 떨어진다</strong> → 소원 성취의 기회. 빨리 빌어요!"},{t:"<strong>우주를 여행한다</strong> → 한계를 넘어서는 성장. 큰 비전"},{t:"<strong>블랙홀에 빠진다</strong> → 알 수 없는 미래에 대한 불안"},{t:"<strong>은하수를 본다</strong> → 경이로움. 인생의 큰 그림을 보는 시기"}]},{e:"📚",n:"책/공부",cat:"물건",tags:["중립"],meaning:"책은 지식, 발견, 자기 성장을 상징해요.",contexts:[{t:"<strong>책을 읽는다</strong> → 배움의 시기. 새로운 정보가 필요해요"},{t:"<strong>빈 책을 펼친다</strong> → 아직 쓰여지지 않은 미래. 가능성"},{t:"<strong>오래된 책을 발견한다</strong> → 잊었던 지혜나 기억이 되살아나요"},{t:"<strong>책이 찢어진다</strong> → 계획이 틀어지거나 정보가 부족한 상태"}]},{e:"🪞",n:"거울",cat:"물건",tags:["중립"],meaning:"거울은 자기 인식, 진실, 자아 성찰의 상징.",contexts:[{t:"<strong>거울을 본다</strong> → 자기 자신을 객관적으로 바라보는 시기"},{t:"<strong>거울 속 내가 다르게 보인다</strong> → 정체성의 변화. 새로운 나"},{t:"<strong>거울이 깨진다</strong> → 자기 이미지가 흔들리는 상태"},{t:"<strong>거울 속에 다른 사람이 보인다</strong> → 그 사람의 특성이 내 안에도 있어요"}]},{e:"💎",n:"보석/귀금속",cat:"물건",tags:["길몽","대길"],meaning:"보석은 내면의 가치, 재능, 소중한 것을 상징해요.",contexts:[{t:"<strong>다이아몬드를 발견한다</strong> → 숨겨진 재능이나 가치를 깨달아요"},{t:"<strong>금을 캔다</strong> → 노력의 대가. 큰 보상이 찾아와요"},{t:"<strong>보석을 선물받는다</strong> → 소중한 인연이나 기회"},{t:"<strong>보석을 잃어버린다</strong> → 중요한 것을 놓치고 있어요"},{t:"<strong>진주</strong> → 눈물의 결정. 고통 뒤에 오는 아름다움"}]},{e:"⌚",n:"시계/시간",cat:"물건",tags:["중립"],meaning:"시계는 시간의 흐름, 기한, 인생의 속도를 상징해요.",contexts:[{t:"<strong>시계가 멈춰있다</strong> → 정체된 느낌. 변화가 필요해요"},{t:"<strong>시계가 빨리 간다</strong> → 시간이 부족하다는 압박감"},{t:"<strong>시계를 선물받는다</strong> → 중요한 시기가 다가오고 있어요"},{t:"<strong>알람이 울린다</strong> → 무언가를 놓치지 말라는 경고"}]},{e:"🎁",n:"선물/상자",cat:"물건",tags:["길몽"],meaning:"선물은 축복, 기대, 숨겨진 보상을 상징해요.",contexts:[{t:"<strong>선물을 받는다</strong> → 예상치 못한 행운이나 기회"},{t:"<strong>선물을 준다</strong> → 나눔의 기쁨. 베풀면 돌아와요"},{t:"<strong>상자를 열었는데 비어있다</strong> → 기대가 크면 실망도 큰 법"},{t:"<strong>포장을 뜯는다</strong> → 비밀이 밝혀지거나 진실을 알게 돼요"}]},{e:"🔫",n:"무기/도구",cat:"물건",tags:["주의"],meaning:"무기는 힘, 공격성, 방어 본능을 상징해요.",contexts:[{t:"<strong>칼을 들고 있다</strong> → 결단이 필요한 시기. 끊어야 할 것"},{t:"<strong>활을 쏜다</strong> → 목표를 향해 집중하고 있어요"},{t:"<strong>방패를 든다</strong> → 자신을 보호하려는 본능"},{t:"<strong>무기를 버린다</strong> → 갈등을 포기하고 평화를 택하는 결정"}]},{e:"🏪",n:"가게/쇼핑",cat:"장소",tags:["중립"],meaning:"가게는 선택, 가치 교환, 욕구를 상징해요.",contexts:[{t:"<strong>쇼핑을 한다</strong> → 선택의 기로. 무엇이 진짜 필요한지 고민"},{t:"<strong>물건을 살 돈이 없다</strong> → 자원 부족에 대한 불안"},{t:"<strong>빈 가게</strong> → 기회가 없다고 느끼는 상태"},{t:"<strong>물건이 넘치는 가게</strong> → 가능성이 많아요. 골라야 해요"}]},{e:"🏟️",n:"경기장/무대",cat:"장소",tags:["중립"],meaning:"무대는 주목, 평가, 자기 표현의 상징.",contexts:[{t:"<strong>무대에 올라간다</strong> → 주목받을 일이 생겨요"},{t:"<strong>관중이 환호한다</strong> → 인정과 성취. 자신감 상승"},{t:"<strong>무대에서 실수한다</strong> → 평가에 대한 불안"},{t:"<strong>텅 빈 객석</strong> → 외로움이나 인정받지 못하는 느낌"}]},{e:"🌲",n:"숲/정글",cat:"장소",tags:["중립"],meaning:"숲은 무의식, 미지의 영역, 자연으로의 회귀를 상징해요.",contexts:[{t:"<strong>숲을 걷는다</strong> → 자기 탐색의 여정. 내면을 돌아보는 시기"},{t:"<strong>숲에서 길을 잃는다</strong> → 인생의 방향을 모르겠는 상태"},{t:"<strong>밝은 숲</strong> → 성장과 치유. 자연스러운 회복"},{t:"<strong>어두운 숲</strong> → 두려운 무의식 영역. 용기가 필요해요"},{t:"<strong>숲에서 동물을 만난다</strong> → 본능적 자아와의 만남"}]},{e:"🏰",n:"궁전/성",cat:"장소",tags:["길몽"],meaning:"궁전은 권력, 꿈의 실현, 높은 이상을 상징해요.",contexts:[{t:"<strong>궁전에 들어간다</strong> → 큰 성취나 지위 상승의 전조"},{t:"<strong>왕좌에 앉는다</strong> → 리더십을 발휘할 시기"},{t:"<strong>궁전이 무너진다</strong> → 권위나 체계에 대한 의문"},{t:"<strong>궁전을 구경한다</strong> → 큰 목표를 꿈꾸는 상태"}]},{e:"🚉",n:"역/터미널",cat:"장소",tags:["중립"],meaning:"역은 출발, 전환점, 기다림의 상징.",contexts:[{t:"<strong>기차를 기다린다</strong> → 변화를 앞두고 준비하는 시기"},{t:"<strong>기차를 놓친다</strong> → 기회를 놓칠까 봐 조급한 마음"},{t:"<strong>공항에 있다</strong> → 큰 변화나 여행이 다가오고 있어요"},{t:"<strong>목적지 없이 탄다</strong> → 방향을 잃은 상태. 목표 재설정 필요"}]},{e:"⛪",n:"절/교회/사찰",cat:"장소",tags:["길몽"],meaning:"종교 공간은 영적 안식, 치유, 답을 구하는 마음의 상징.",contexts:[{t:"<strong>기도한다</strong> → 간절한 소원이 있어요. 마음을 정리하는 시기"},{t:"<strong>종소리를 듣는다</strong> → 중요한 깨달음이 찾아올 징조"},{t:"<strong>절에서 불상을 본다</strong> → 내면의 평화를 찾아가는 과정"},{t:"<strong>성당에서 빛이 들어온다</strong> → 축복과 보호. 좋은 기운"}]},{e:"🎤",n:"말하기/발표",cat:"행동",tags:["중립"],meaning:"말하는 꿈은 표현 욕구, 소통, 자기주장을 상징해요.",contexts:[{t:"<strong>목소리가 안 나온다</strong> → 표현하지 못한 감정이 쌓여 있어요"},{t:"<strong>큰 소리로 말한다</strong> → 자기주장이 필요한 시기"},{t:"<strong>외국어로 말한다</strong> → 새로운 소통 방식을 배우는 과정"},{t:"<strong>노래를 부른다</strong> → 감정 표현. 마음속 이야기를 전하고 싶어요"}]},{e:"🏃‍♀️",n:"운동/경쟁",cat:"행동",tags:["중립"],meaning:"운동은 경쟁, 자기 극복, 에너지 발산을 상징해요.",contexts:[{t:"<strong>달리기에서 1등</strong> → 목표 달성! 노력이 보상받아요"},{t:"<strong>경기에서 진다</strong> → 좌절이지만 배움의 기회"},{t:"<strong>수영을 한다</strong> → 감정 속을 헤쳐나가는 과정"},{t:"<strong>등산한다</strong> → 목표를 향해 힘들지만 올라가는 중"}]},{e:"🧹",n:"청소/정리",cat:"행동",tags:["길몽"],meaning:"청소는 마음의 정화, 과거 정리, 새 시작 준비를 상징해요.",contexts:[{t:"<strong>방을 청소한다</strong> → 마음을 정리하는 과정. 좋은 변화 전조"},{t:"<strong>쓰레기를 버린다</strong> → 불필요한 것을 놓아주는 시기"},{t:"<strong>빨래를 한다</strong> → 감정 정화. 깨끗한 새 출발"},{t:"<strong>먼지를 닦는다</strong> → 오래된 문제를 해결하는 과정"}]},{e:"🎨",n:"그리기/만들기",cat:"행동",tags:["길몽"],meaning:"창작은 자기 표현, 잠재력 실현, 내면의 목소리를 상징해요.",contexts:[{t:"<strong>그림을 그린다</strong> → 창조적 에너지가 솟아나요"},{t:"<strong>무언가를 만든다</strong> → 새로운 것을 시작할 준비가 됐어요"},{t:"<strong>완성된 작품을 본다</strong> → 성취감. 노력의 결과를 확인"},{t:"<strong>색칠을 한다</strong> → 삶에 색을 입히고 싶은 욕구"}]},{e:"💋",n:"키스/사랑",cat:"행동",tags:["연애운"],meaning:"키스는 친밀감, 수용, 사랑의 직접적 상징.",contexts:[{t:"<strong>좋아하는 사람과 키스</strong> → 그 사람과의 연결을 원하는 마음"},{t:"<strong>모르는 사람과 키스</strong> → 새로운 경험이나 인연에 대한 기대"},{t:"<strong>이마에 키스</strong> → 보호와 축복. 안전한 사랑"},{t:"<strong>키스를 거절당한다</strong> → 거절에 대한 두려움. 자존감 점검"}]},{e:"😭",n:"울음/웃음",cat:"행동",tags:["중립"],meaning:"울음은 감정 해방, 웃음은 기쁨이나 긴장 해소를 상징해요.",contexts:[{t:"<strong>펑펑 운다</strong> → 억눌렸던 감정이 터지는 과정. 정화"},{t:"<strong>기쁨에 운다</strong> → 큰 감동이나 성취가 다가오고 있어요"},{t:"<strong>크게 웃는다</strong> → 스트레스 해소. 좋은 일이 올 징조"},{t:"<strong>울고 싶은데 못 운다</strong> → 감정 억압. 표현할 공간이 필요해요"}]},{e:"❤️",n:"심장/가슴",cat:"신체",tags:["중립"],meaning:"심장은 감정의 핵심, 사랑, 생명력을 상징해요.",contexts:[{t:"<strong>심장이 빨리 뛴다</strong> → 흥분이나 불안. 중요한 일이 다가와요"},{t:"<strong>가슴이 아프다</strong> → 감정적 상처. 치유가 필요해요"},{t:"<strong>심장이 빛난다</strong> → 사랑의 에너지. 좋은 인연의 신호"},{t:"<strong>가슴이 따뜻하다</strong> → 안도감과 사랑. 보호받고 있어요"}]},{e:"🦶",n:"다리/걷기",cat:"신체",tags:["중립"],meaning:"다리는 앞으로 나아가는 힘, 기반, 독립을 상징해요.",contexts:[{t:"<strong>다리가 아프다</strong> → 앞으로 나아가기 힘든 상태"},{t:"<strong>다리가 없어졌다</strong> → 기반이 흔들리는 느낌. 불안정"},{t:"<strong>빠르게 걷는다</strong> → 목표를 향해 적극적으로 가고 있어요"},{t:"<strong>맨발로 걷는다</strong> → 자연과 연결. 본래의 자신으로 돌아가기"}]},{e:"🫁",n:"숨/호흡",cat:"신체",tags:["주의"],meaning:"호흡은 생명력, 자유, 감정 상태를 직접 반영해요.",contexts:[{t:"<strong>숨을 못 쉰다</strong> → 현실에서 숨 막히는 압박감"},{t:"<strong>깊게 숨을 쉰다</strong> → 안도감. 긴장이 풀리는 시기"},{t:"<strong>물속에서 숨을 쉰다</strong> → 감정 속에서도 평온을 유지하는 능력"},{t:"<strong>숨이 하얗게 보인다</strong> → 차가운 환경. 감정적으로 냉각된 상태"}]},{e:"👂",n:"귀/소리",cat:"신체",tags:["중립"],meaning:"귀는 경청, 직감, 메시지 수신을 상징해요.",contexts:[{t:"<strong>이상한 소리가 들린다</strong> → 무의식이 보내는 신호. 주의를 기울이세요"},{t:"<strong>귀가 안 들린다</strong> → 주변 의견을 차단하고 있는 상태"},{t:"<strong>아름다운 음악이 들린다</strong> → 영적 성장이나 감동적 경험의 전조"},{t:"<strong>속삭임이 들린다</strong> → 비밀이나 중요한 정보를 얻게 돼요"}]},{e:"👩‍💼",n:"직장/상사",cat:"사람",tags:["중립"],meaning:"직장 관련 꿈은 업무 스트레스, 성취욕, 권력 관계를 반영해요.",contexts:[{t:"<strong>상사에게 칭찬받는다</strong> → 인정받고 싶은 욕구. 곧 좋은 평가"},{t:"<strong>상사에게 혼난다</strong> → 현실의 업무 압박이 꿈으로 표출"},{t:"<strong>동료와 협력한다</strong> → 팀워크가 중요한 시기"},{t:"<strong>해고당한다</strong> → 역꿈일 가능성. 오히려 새 기회의 전조"},{t:"<strong>승진한다</strong> → 자신감 상승. 노력이 인정받는 시기"}]},{e:"👫",n:"친구",cat:"사람",tags:["중립"],meaning:"친구 꿈은 사회적 관계, 지지 체계, 자기 투영을 반영해요.",contexts:[{t:"<strong>오래된 친구를 만난다</strong> → 과거의 나를 그리워하는 마음"},{t:"<strong>친구와 싸운다</strong> → 현실에서 말 못한 감정이 있어요"},{t:"<strong>친구가 도와준다</strong> → 곧 주변에서 도움이 올 거예요"},{t:"<strong>친구가 사라진다</strong> → 관계 변화에 대한 불안"}]},{e:"👶",n:"어린 시절/과거",cat:"사람",tags:["중립"],meaning:"어린 시절 꿈은 순수함, 근원, 미해결된 과거를 반영해요.",contexts:[{t:"<strong>어린 시절 집에 있다</strong> → 안전했던 시기에 대한 향수"},{t:"<strong>어린 나를 본다</strong> → 잃어버린 순수함을 되찾고 싶은 마음"},{t:"<strong>학교 시절로 돌아간다</strong> → 성장기의 미해결 과제가 있어요"},{t:"<strong>옛 동네를 걷는다</strong> → 자기 뿌리를 확인하려는 욕구"}]},{e:"🐺",n:"늑대",cat:"동물",tags:["중립"],meaning:"늑대는 본능, 자유, 경계심의 상징.",contexts:[{t:"<strong>늑대가 울부짖는다</strong> → 외로움이나 소속감에 대한 갈망"},{t:"<strong>늑대 무리</strong> → 팀워크와 충성. 주변 사람들의 중요성"},{t:"<strong>늑대에게 쫓긴다</strong> → 위협적인 사람이나 상황에서 도망치고 싶은 마음"},{t:"<strong>늑대를 길들인다</strong> → 자신의 야성적인 면을 통제하는 과정"}]},{e:"🦊",n:"여우",cat:"동물",tags:["주의"],meaning:"여우는 영리함, 속임수, 적응력의 상징.",contexts:[{t:"<strong>여우가 나타났다</strong> → 주변에 교활한 사람이 있을 수 있어요"},{t:"<strong>여우를 쫓는다</strong> → 진실을 파헤치려는 노력"},{t:"<strong>하얀 여우</strong> → 신령의 상징. 좋은 기운이 찾아와요"},{t:"<strong>여우가 웃는다</strong> → 누군가의 속내를 간파해야 해요"}]},{e:"🐻",n:"곰",cat:"동물",tags:["중립"],meaning:"곰은 힘, 보호, 겨울잠(휴식)의 상징.",contexts:[{t:"<strong>곰이 다가온다</strong> → 강한 보호자나 위협적 존재의 등장"},{t:"<strong>곰이 잠을 잔다</strong> → 지금은 쉬어야 할 때. 재충전"},{t:"<strong>아기 곰</strong> → 순수하지만 강한 잠재력"},{t:"<strong>곰에게 쫓긴다</strong> → 감당하기 어려운 문제를 피하고 있어요"}]},{e:"🦌",n:"사슴",cat:"동물",tags:["길몽"],meaning:"사슴은 우아함, 영적 메시지, 순수함의 상징.",contexts:[{t:"<strong>사슴이 다가온다</strong> → 평화로운 시기. 영적 성장"},{t:"<strong>사슴 뿔</strong> → 성장과 재생. 새로운 가능성"},{t:"<strong>흰 사슴</strong> → 신성한 존재. 큰 행운의 전조"}]},{e:"🐰",n:"토끼",cat:"동물",tags:["길몽"],meaning:"토끼는 다산, 행운, 민첩함의 상징.",contexts:[{t:"<strong>토끼가 뛰어다닌다</strong> → 기회가 빠르게 지나가요. 잡아야 해요"},{t:"<strong>토끼를 안는다</strong> → 행운을 손에 넣었어요"},{t:"<strong>토끼 굴</strong> → 미지의 세계로의 탐험. 모험심"},{t:"<strong>달토끼</strong> → 소원 성취의 전통적 상징"}]},{e:"🐦",n:"까마귀/비둘기",cat:"동물",tags:["중립"],meaning:"까마귀는 변화의 전조, 비둘기는 평화의 메신저.",contexts:[{t:"<strong>까마귀가 운다</strong> → 변화가 다가와요. 주의 깊게 준비하세요"},{t:"<strong>비둘기가 날아온다</strong> → 평화로운 소식이 올 거예요"},{t:"<strong>새 떼가 하늘을 난다</strong> → 자유에 대한 갈망. 해방감"},{t:"<strong>앵무새</strong> → 누군가의 말을 따라하고 있진 않나요"}]},{e:"🦎",n:"도마뱀/파충류",cat:"동물",tags:["중립"],meaning:"파충류는 원시적 본능, 적응력, 재생의 상징.",contexts:[{t:"<strong>도마뱀이 꼬리를 자른다</strong> → 과거를 버리고 재생하는 과정"},{t:"<strong>악어가 나타났다</strong> → 숨겨진 위험. 표면 아래를 살펴보세요"},{t:"<strong>카멜레온</strong> → 상황에 맞게 변하는 적응력"}]},{e:"🐝",n:"벌/꿀",cat:"동물",tags:["길몽"],meaning:"벌은 근면, 협동, 달콤한 보상의 상징.",contexts:[{t:"<strong>벌이 꿀을 만든다</strong> → 노력의 달콤한 결실이 다가와요"},{t:"<strong>벌에 쏘인다</strong> → 작지만 아픈 교훈. 주의 필요"},{t:"<strong>벌집</strong> → 공동체와 조직. 팀의 중요성"},{t:"<strong>꿀을 먹는다</strong> → 달콤한 보상. 행복한 시기"}]},{e:"🐛",n:"나비/애벌레",cat:"동물",tags:["길몽"],meaning:"나비는 완전한 변신, 아름다움, 자유의 상징.",contexts:[{t:"<strong>나비가 날아온다</strong> → 아름다운 변화가 다가와요"},{t:"<strong>애벌레를 본다</strong> → 변화 전 준비 단계. 인내가 필요해요"},{t:"<strong>나비가 손에 앉는다</strong> → 행운과 아름다움을 손에 넣었어요"},{t:"<strong>나비가 날아간다</strong> → 아름다운 순간은 일시적. 감사하며 보내기"}]},{e:"🐊",n:"악어/뱀장어",cat:"동물",tags:["주의"],meaning:"악어는 숨겨진 위험, 원시적 공포, 잠재된 힘의 상징.",contexts:[{t:"<strong>악어가 물속에 있다</strong> → 겉으로 안 보이는 위험이 있어요"},{t:"<strong>악어에게 물린다</strong> → 신뢰했던 것에 배신당할 수 있어요"},{t:"<strong>악어를 피한다</strong> → 위기를 잘 넘기고 있어요"}]},{e:"🐋",n:"고래/돌고래",cat:"동물",tags:["길몽"],meaning:"고래는 깊은 감정, 영성, 웅장함의 상징.",contexts:[{t:"<strong>고래가 바다에서 뛰어오른다</strong> → 감정의 폭발적 해방. 큰 깨달음"},{t:"<strong>돌고래와 수영한다</strong> → 즐거움과 자유. 좋은 인연"},{t:"<strong>고래 소리를 듣는다</strong> → 깊은 내면의 메시지. 직감을 따르세요"}]},{e:"🚇",n:"지하철/버스",cat:"장소",tags:["중립"],meaning:"대중교통은 인생의 방향, 사회적 흐름, 공동체를 상징.",contexts:[{t:"<strong>지하철을 탄다</strong> → 정해진 경로를 따라가고 있어요"},{t:"<strong>버스를 놓친다</strong> → 기회를 놓칠까 봐 조급한 마음"},{t:"<strong>잘못된 방향으로 간다</strong> → 인생 방향 재점검이 필요해요"},{t:"<strong>만원 지하철</strong> → 사회적 압박감. 숨 막히는 일상"}]},{e:"🚽",n:"화장실",cat:"장소",tags:["길몽"],meaning:"화장실은 정화, 해소, 사적 공간의 상징. 전통적으로 재물 길몽.",contexts:[{t:"<strong>화장실을 찾는다</strong> → 해결해야 할 급한 문제가 있어요"},{t:"<strong>화장실이 더럽다</strong> → 전통 해몽에서 오히려 재물 길조!"},{t:"<strong>화장실을 못 찾는다</strong> → 감정을 표현할 공간이 없는 상태"},{t:"<strong>깨끗한 화장실</strong> → 마음이 정리되고 있어요"}]},{e:"🛁",n:"목욕/샤워",cat:"장소",tags:["길몽"],meaning:"목욕은 정화, 재탄생, 스트레스 해소의 상징.",contexts:[{t:"<strong>따뜻한 물로 목욕한다</strong> → 마음의 치유. 스트레스 해소"},{t:"<strong>찬물 샤워</strong> → 정신 차리기. 각성의 시기"},{t:"<strong>온천에 간다</strong> → 휴식이 절실해요. 재충전 시기"},{t:"<strong>때를 밀다</strong> → 과거의 묵은 것을 정리하는 과정"}]},{e:"🎢",n:"놀이공원",cat:"장소",tags:["중립"],meaning:"놀이공원은 즐거움, 일탈, 어린 시절의 향수.",contexts:[{t:"<strong>놀이기구를 탄다</strong> → 인생의 롤러코스터. 기복이 있는 시기"},{t:"<strong>회전목마</strong> → 같은 자리를 맴도는 느낌. 변화 필요"},{t:"<strong>관람차 꼭대기</strong> → 높은 곳에서 전체를 바라보는 시기"},{t:"<strong>귀신의 집</strong> → 두려움을 즐기고 있어요. 스릴"}]},{e:"🏨",n:"호텔/여관",cat:"장소",tags:["중립"],meaning:"호텔은 임시적 머무름, 전환기, 자기 돌봄의 상징.",contexts:[{t:"<strong>호텔에 체크인한다</strong> → 일시적 휴식. 전환기에 있어요"},{t:"<strong>호텔 방이 넓다</strong> → 새로운 가능성이 열려 있어요"},{t:"<strong>방을 못 찾는다</strong> → 자리를 찾지 못하는 불안감"}]},{e:"🏖️",n:"섬",cat:"장소",tags:["중립"],meaning:"섬은 고립, 독립, 자기만의 세계를 상징.",contexts:[{t:"<strong>무인도에 있다</strong> → 고독감이지만 자기 발견의 기회"},{t:"<strong>아름다운 섬</strong> → 이상향. 꿈꾸는 삶에 대한 갈망"},{t:"<strong>섬에서 탈출한다</strong> → 고립에서 벗어나려는 노력"}]},{e:"🕳️",n:"동굴/지하",cat:"장소",tags:["중립"],meaning:"동굴은 무의식의 깊은 곳, 숨겨진 것, 탐험의 상징.",contexts:[{t:"<strong>동굴에 들어간다</strong> → 자기 내면을 깊이 탐구하는 시기"},{t:"<strong>동굴에서 보물을 발견</strong> → 숨겨진 재능이나 해답을 찾아요"},{t:"<strong>동굴에서 나온다</strong> → 고민 끝에 답을 찾는 과정"},{t:"<strong>어두운 동굴</strong> → 두려움을 직면해야 해요"}]},{e:"🏜️",n:"사막",cat:"장소",tags:["주의"],meaning:"사막은 고갈, 시련, 정화의 상징.",contexts:[{t:"<strong>사막을 걷는다</strong> → 힘든 시기지만 끝이 있어요"},{t:"<strong>오아시스를 발견한다</strong> → 어려움 속 희망. 구원의 손길"},{t:"<strong>모래폭풍</strong> → 혼란 속에서 방향을 잃은 상태"}]},{e:"👜",n:"가방/짐",cat:"물건",tags:["중립"],meaning:"가방은 짐, 책임, 준비 상태를 상징.",contexts:[{t:"<strong>가방을 싼다</strong> → 변화를 준비하고 있어요"},{t:"<strong>가방을 잃어버린다</strong> → 정체성이나 중요한 것을 놓치는 느낌"},{t:"<strong>무거운 가방</strong> → 책임감이 무겁게 느껴지는 상태"},{t:"<strong>가방이 비어있다</strong> → 준비가 안 됐다는 불안"}]},{e:"👟",n:"신발",cat:"물건",tags:["중립"],meaning:"신발은 사회적 위치, 역할, 인생의 방향을 상징.",contexts:[{t:"<strong>새 신발을 신는다</strong> → 새로운 역할이나 시작"},{t:"<strong>신발을 잃어버린다</strong> → 기반을 잃는 느낌. 불안정"},{t:"<strong>맞지 않는 신발</strong> → 자신에게 맞지 않는 역할을 하고 있어요"},{t:"<strong>구두/하이힐</strong> → 사회적 이미지에 대한 의식"}]},{e:"🌂",n:"우산",cat:"물건",tags:["중립"],meaning:"우산은 보호, 방어, 준비성의 상징.",contexts:[{t:"<strong>우산을 쓴다</strong> → 누군가가 지켜주고 있어요"},{t:"<strong>우산이 부서진다</strong> → 보호막이 무너지는 느낌"},{t:"<strong>우산 없이 비를 맞는다</strong> → 무방비 상태. 하지만 정화일 수도"}]},{e:"💻",n:"컴퓨터/인터넷",cat:"물건",tags:["중립"],meaning:"컴퓨터는 소통, 정보, 현대적 연결의 상징.",contexts:[{t:"<strong>컴퓨터가 고장난다</strong> → 소통 단절이나 정보 처리 과부하"},{t:"<strong>인터넷 검색을 한다</strong> → 답을 찾고 있는 상태"},{t:"<strong>바이러스에 감염</strong> → 유해한 정보나 영향에 주의"},{t:"<strong>게임을 한다</strong> → 현실 도피 욕구이거나 전략적 사고"}]},{e:"📷",n:"카메라/사진",cat:"물건",tags:["중립"],meaning:"카메라는 기억, 관점, 순간 포착의 상징.",contexts:[{t:"<strong>사진을 찍는다</strong> → 이 순간을 기억하고 싶은 마음"},{t:"<strong>오래된 사진을 본다</strong> → 과거에 대한 그리움"},{t:"<strong>사진이 흐릿하다</strong> → 기억이나 판단이 불분명한 상태"},{t:"<strong>셀카를 찍는다</strong> → 자기 이미지에 대한 관심"}]},{e:"🗺️",n:"지도/나침반",cat:"물건",tags:["길몽"],meaning:"지도는 방향, 계획, 인생의 경로를 상징.",contexts:[{t:"<strong>지도를 펼친다</strong> → 인생 계획을 세우는 시기"},{t:"<strong>나침반이 가리키는 방향</strong> → 직감이 답을 알고 있어요"},{t:"<strong>지도를 잃어버린다</strong> → 방향을 잃은 느낌"}]},{e:"🎭",n:"마스크/가면",cat:"물건",tags:["중립"],meaning:"가면은 페르소나(사회적 얼굴), 숨김, 보호를 상징.",contexts:[{t:"<strong>가면을 쓴다</strong> → 진짜 자신을 숨기고 있어요"},{t:"<strong>가면을 벗는다</strong> → 진실된 모습을 드러낼 용기"},{t:"<strong>다른 사람이 가면을 쓴다</strong> → 그 사람의 진심을 의심하고 있어요"}]},{e:"✉️",n:"편지/메시지",cat:"물건",tags:["중립"],meaning:"편지는 전달되지 못한 마음, 소식, 비밀의 상징.",contexts:[{t:"<strong>편지를 받는다</strong> → 소식이 올 거예요. 기대하세요"},{t:"<strong>편지를 쓴다</strong> → 전하고 싶은 말이 있어요"},{t:"<strong>편지를 읽지 못한다</strong> → 중요한 메시지를 놓치고 있어요"},{t:"<strong>연애편지</strong> → 사랑에 대한 갈망이나 표현 욕구"}]},{e:"🍳",n:"요리",cat:"행동",tags:["길몽"],meaning:"요리는 창조, 준비, 사랑의 표현.",contexts:[{t:"<strong>맛있는 요리를 만든다</strong> → 창조적 에너지. 좋은 결과가 나와요"},{t:"<strong>요리를 태운다</strong> → 서두르면 일을 그르칠 수 있어요"},{t:"<strong>다른 사람에게 요리해준다</strong> → 사랑과 돌봄을 표현하는 방식"}]},{e:"🎵",n:"악기/음악",cat:"행동",tags:["길몽"],meaning:"음악은 감정 표현, 조화, 영혼의 언어.",contexts:[{t:"<strong>피아노를 친다</strong> → 감정을 아름답게 표현하고 있어요"},{t:"<strong>기타를 연주한다</strong> → 자유로운 자기 표현"},{t:"<strong>음악이 들린다</strong> → 영적 메시지나 영감의 전조"},{t:"<strong>악기가 고장난다</strong> → 표현이 막혀 있는 상태"}]},{e:"🧗",n:"등반/오르기",cat:"행동",tags:["중립"],meaning:"오르기는 도전, 성장, 목표 추구의 상징.",contexts:[{t:"<strong>절벽을 오른다</strong> → 어렵지만 포기하지 않는 도전"},{t:"<strong>사다리를 오른다</strong> → 단계적 성장. 차근차근"},{t:"<strong>정상에 도달한다</strong> → 목표 달성! 큰 성취"},{t:"<strong>미끄러진다</strong> → 좌절이지만 다시 시도할 수 있어요"}]},{e:"🤝",n:"악수/만남",cat:"행동",tags:["길몽"],meaning:"악수는 합의, 새 인연, 협력의 상징.",contexts:[{t:"<strong>누군가와 악수한다</strong> → 좋은 만남이나 계약의 전조"},{t:"<strong>포옹한다</strong> → 화해나 깊은 유대감"},{t:"<strong>모르는 사람과 만난다</strong> → 새로운 가능성의 등장"}]},{e:"🏊‍♂️",n:"잠수/물속",cat:"행동",tags:["중립"],meaning:"물속은 무의식의 깊은 곳, 감정 탐험.",contexts:[{t:"<strong>깊이 잠수한다</strong> → 자기 내면을 깊이 탐구하는 용기"},{t:"<strong>물속에서 보물을 발견</strong> → 숨겨진 가치를 찾아요"},{t:"<strong>숨을 참고 있다</strong> → 감정을 억누르고 있는 상태"},{t:"<strong>물속 동굴을 탐험</strong> → 미지의 자아 탐색"}]},{e:"🌋",n:"화산/지진",cat:"자연",tags:["흉몽"],meaning:"화산은 억압된 감정의 폭발, 지진은 기반이 흔들리는 변화.",contexts:[{t:"<strong>화산이 폭발한다</strong> → 억눌린 분노나 감정이 터질 시기"},{t:"<strong>지진이 난다</strong> → 삶의 기반이 흔들리는 큰 변화"},{t:"<strong>용암이 흐른다</strong> → 파괴적이지만 새로운 땅을 만드는 과정"},{t:"<strong>지진 후 잔해</strong> → 변화 후 재건의 시작"}]},{e:"🌪️",n:"태풍/토네이도",cat:"자연",tags:["흉몽"],meaning:"태풍은 통제 불능의 변화, 감정의 소용돌이.",contexts:[{t:"<strong>태풍에 휘말린다</strong> → 감당 안 되는 상황에 처해 있어요"},{t:"<strong>태풍이 지나간다</strong> → 힘든 시기가 끝나가고 있어요"},{t:"<strong>토네이도를 본다</strong> → 멀리서 보는 위기. 대비할 시간 있어요"}]},{e:"🌄",n:"일출/일몰",cat:"자연",tags:["길몽"],meaning:"일출은 새 시작, 일몰은 한 단계의 마무리.",contexts:[{t:"<strong>아름다운 일출</strong> → 새로운 시작! 희망찬 시기"},{t:"<strong>일몰을 바라본다</strong> → 하나의 단계가 끝나가고 있어요"},{t:"<strong>새벽빛</strong> → 어둠 뒤의 빛. 곧 좋아질 거예요"}]},{e:"🌺",n:"나무/숲",cat:"자연",tags:["길몽"],meaning:"나무는 성장, 뿌리, 생명력의 상징.",contexts:[{t:"<strong>큰 나무</strong> → 안정감과 성장. 튼튼한 기반"},{t:"<strong>나무에 열매가 달렸다</strong> → 노력의 결실을 거두는 시기"},{t:"<strong>나무가 쓰러진다</strong> → 의지했던 것이 무너지는 느낌"},{t:"<strong>나무를 심는다</strong> → 미래를 위한 투자. 장기적 성장"},{t:"<strong>벚꽃이 핀다</strong> → 아름답지만 짧은 시기. 감사하며 즐기세요"}]},{e:"❄️",n:"눈/얼음",cat:"자연",tags:["중립"],meaning:"눈은 순수함과 정적, 얼음은 감정의 동결.",contexts:[{t:"<strong>눈이 내린다</strong> → 새하얀 새 시작. 순수함의 회복"},{t:"<strong>눈사람을 만든다</strong> → 즐거움과 창의성"},{t:"<strong>얼음 위를 걷는다</strong> → 불안정한 상황. 조심해서 나아가야 해요"},{t:"<strong>얼음이 녹는다</strong> → 차가웠던 감정이 풀리는 과정"}]},{e:"👮",n:"경찰/군인",cat:"사람",tags:["중립"],meaning:"경찰은 규칙, 권위, 양심의 상징.",contexts:[{t:"<strong>경찰이 다가온다</strong> → 죄책감이나 규칙에 대한 의식"},{t:"<strong>경찰에게 잡힌다</strong> → 비밀이 드러날까 봐 두려운 마음"},{t:"<strong>군인이 된다</strong> → 규율과 훈련이 필요한 시기"},{t:"<strong>군대에 있다</strong> → 자유가 억압된 느낌"}]},{e:"👴",n:"할아버지/할머니",cat:"사람",tags:["길몽"],meaning:"조부모는 지혜, 근원, 수호의 상징.",contexts:[{t:"<strong>돌아가신 조부모가 나타났다</strong> → 수호와 보호. 좋은 기운"},{t:"<strong>조부모가 밥을 차려준다</strong> → 최고의 길몽! 큰 복이 와요"},{t:"<strong>조부모가 웃으신다</strong> → 축복과 안심. 잘 하고 있어요"},{t:"<strong>조부모가 손짓하신다</strong> → 건강 주의. 쉼이 필요해요"},{t:"<strong>조부모에게 용돈 받는다</strong> → 재물 길조! 뜻밖의 수입"}]},{e:"👫",n:"형제/자매",cat:"사람",tags:["중립"],meaning:"형제는 경쟁, 유대, 자기 분신의 상징.",contexts:[{t:"<strong>형제와 놀다</strong> → 어린 시절의 순수함. 편안한 관계"},{t:"<strong>형제와 싸운다</strong> → 내면의 갈등이나 경쟁심"},{t:"<strong>형제가 위험에 처한다</strong> → 보호 본능. 가족에 대한 걱정"}]},{e:"🧑‍⚕️",n:"의사/간호사",cat:"사람",tags:["중립"],meaning:"의사는 치유, 도움, 전문적 해결의 상징.",contexts:[{t:"<strong>의사에게 진료받는다</strong> → 도움이 필요해요. 전문가를 찾아볼 때"},{t:"<strong>내가 의사가 된다</strong> → 다른 사람을 돕고 싶은 마음"},{t:"<strong>수술을 받는다</strong> → 고통스럽지만 필요한 변화"}]},{e:"👰",n:"신부/신랑",cat:"사람",tags:["연애운"],meaning:"결혼 당사자는 헌신, 결합, 새 단계의 상징.",contexts:[{t:"<strong>내가 결혼한다</strong> → 중요한 결정이나 헌신의 시기"},{t:"<strong>결혼식을 구경한다</strong> → 축하할 일이 생겨요"},{t:"<strong>결혼 준비를 한다</strong> → 인생의 새 단계를 준비하는 과정"}]},{e:"🫀",n:"피/상처",cat:"신체",tags:["주의"],meaning:"피는 생명력, 에너지, 감정적 상처의 상징.",contexts:[{t:"<strong>피가 난다</strong> → 에너지가 소진되고 있어요"},{t:"<strong>피를 본다</strong> → 감정적 상처가 아직 치유 안 됐어요"},{t:"<strong>피가 멈춘다</strong> → 치유가 진행되고 있어요"},{t:"<strong>수혈을 받는다</strong> → 외부에서 에너지를 보충받을 필요"}]},{e:"🦴",n:"뼈/해골",cat:"신체",tags:["중립"],meaning:"뼈는 구조, 본질, 근본의 상징.",contexts:[{t:"<strong>뼈가 드러난다</strong> → 본질이 드러나는 시기. 꾸밈없는 진실"},{t:"<strong>해골을 본다</strong> → 무상함. 중요한 것에 집중할 때"},{t:"<strong>뼈가 부러진다</strong> → 기반이나 원칙이 흔들리는 느낌"}]},{e:"👄",n:"입/혀",cat:"신체",tags:["중립"],meaning:"입은 표현, 소통, 욕구의 상징.",contexts:[{t:"<strong>말이 안 나온다</strong> → 표현하지 못한 감정이 쌓여 있어요"},{t:"<strong>혀가 빠진다</strong> → 비밀을 지키기 어려운 상황"},{t:"<strong>입에서 이물질이 나온다</strong> → 말하지 못했던 것을 뱉어내는 과정"},{t:"<strong>키스</strong> → 친밀감과 수용. 사랑의 표현"}]},{e:"🎈",n:"풍선/연",cat:"기타",tags:["중립"],meaning:"풍선은 가벼움, 희망, 일시적 기쁨의 상징.",contexts:[{t:"<strong>풍선이 날아간다</strong> → 소중한 것을 놓치는 느낌"},{t:"<strong>풍선을 잡고 있다</strong> → 희망을 붙잡고 있어요"},{t:"<strong>풍선이 터진다</strong> → 환상이 깨지는 순간"},{t:"<strong>연을 날린다</strong> → 자유로운 꿈. 높이 날고 싶은 마음"}]},{e:"🧸",n:"인형/장난감",cat:"기타",tags:["중립"],meaning:"인형은 어린 시절, 위로, 대리 감정의 상징.",contexts:[{t:"<strong>인형을 안는다</strong> → 위로가 필요한 상태"},{t:"<strong>인형이 움직인다</strong> → 무의식적 두려움이나 소원"},{t:"<strong>장난감으로 논다</strong> → 순수한 즐거움. 스트레스 해소"}]},{e:"🖼️",n:"그림자/반영",cat:"기타",tags:["중립"],meaning:"그림자는 융 심리학의 핵심 개념. 자기 안의 인정하지 않는 면.",contexts:[{t:"<strong>내 그림자를 본다</strong> → 자기 안의 숨겨진 면과 마주하는 과정"},{t:"<strong>그림자가 따라온다</strong> → 피할 수 없는 자기 자신. 수용 필요"},{t:"<strong>그림자가 사라진다</strong> → 자기 수용이 이뤄지고 있어요"},{t:"<strong>다른 사람의 그림자</strong> → 그 사람이 숨기고 있는 면"}]},{e:"🌡️",n:"온도/날씨감각",cat:"기타",tags:["중립"],meaning:"온도는 감정의 강도를 직접 반영.",contexts:[{t:"<strong>매우 덥다</strong> → 열정이나 분노가 과열된 상태"},{t:"<strong>매우 춥다</strong> → 감정적 냉각. 외로움이나 거리감"},{t:"<strong>시원한 바람</strong> → 안도감과 해방. 상쾌한 변화"},{t:"<strong>습하고 답답하다</strong> → 감정이 무겁고 해소가 안 되는 상태"}]},{e:"👣",n:"발자국/흔적",cat:"기타",tags:["중립"],meaning:"발자국은 지나온 길, 영향력, 존재감의 상징.",contexts:[{t:"<strong>발자국을 따라간다</strong> → 누군가의 길을 따르고 있어요"},{t:"<strong>내 발자국을 돌아본다</strong> → 지나온 인생을 성찰하는 시기"},{t:"<strong>발자국이 사라진다</strong> → 존재감에 대한 불안"},{t:"<strong>눈 위의 발자국</strong> → 순수한 출발의 흔적"}]},{e:"🍼",n:"젖소/우유",cat:"기타",tags:["길몽"],meaning:"우유는 양육, 풍요, 순수함의 상징.",contexts:[{t:"<strong>우유를 마신다</strong> → 영양 보충. 성장과 치유"},{t:"<strong>젖소가 나타났다</strong> → 풍요와 안정의 전조"},{t:"<strong>우유가 넘친다</strong> → 풍요가 넘치는 시기"},{t:"<strong>치즈/버터</strong> → 가공된 풍요. 노력으로 얻은 결실"}]},{e:"🥚",n:"달걀/닭",cat:"기타",tags:["길몽"],meaning:"달걀은 잠재력, 새 생명, 시작의 상징.",contexts:[{t:"<strong>달걀을 발견한다</strong> → 새로운 가능성을 발견했어요"},{t:"<strong>달걀이 부화한다</strong> → 오래 품었던 것이 결실을 맺어요"},{t:"<strong>달걀이 깨진다</strong> → 준비되기 전에 드러나는 것에 주의"},{t:"<strong>닭이 알을 낳는다</strong> → 작지만 확실한 결실. 재물 길조"},{t:"<strong>수탉이 운다</strong> → 새벽. 새 시작을 알리는 신호"}]},{e:"🦅",n:"독수리/매",cat:"동물",tags:["길몽","대길"],meaning:"맹금류는 시야, 권력, 자유의 최상급 상징.",contexts:[{t:"<strong>독수리가 하늘 높이 난다</strong> → 큰 성취와 높은 시야를 얻는 시기"},{t:"<strong>매가 먹이를 낚아챈다</strong> → 기회를 정확히 포착! 행동할 때"},{t:"<strong>독수리 발톱</strong> → 강한 의지와 결단력의 상징"},{t:"<strong>매가 어깨에 앉는다</strong> → 권력자의 인정이나 보호"}]},{e:"🐒",n:"원숭이",cat:"동물",tags:["중립"],meaning:"원숭이는 장난기, 지능, 모방의 상징.",contexts:[{t:"<strong>원숭이가 장난친다</strong> → 가벼운 마음으로 접근해야 할 일"},{t:"<strong>원숭이를 따라간다</strong> → 호기심. 새로운 것을 배우는 과정"},{t:"<strong>원숭이 떼</strong> → 사회적 관계의 복잡함"},{t:"<strong>원숭이가 과일을 준다</strong> → 예상치 못한 곳에서 도움"}]},{e:"🦜",n:"앵무새/공작",cat:"동물",tags:["중립"],meaning:"화려한 새는 자기 표현, 모방, 아름다움의 상징.",contexts:[{t:"<strong>앵무새가 말을 따라한다</strong> → 자기만의 목소리를 찾아야 해요"},{t:"<strong>공작이 깃털을 펼친다</strong> → 자기 과시 욕구. 인정받고 싶은 마음"},{t:"<strong>새장 속의 새</strong> → 자유가 억압된 상태"}]},{e:"🐌",n:"달팽이/거북이류",cat:"동물",tags:["중립"],meaning:"느린 동물은 인내, 자기 보호, 느리지만 확실한 진전.",contexts:[{t:"<strong>달팽이가 기어간다</strong> → 느리지만 확실하게 전진하고 있어요"},{t:"<strong>달팽이 껍데기에 숨는다</strong> → 자기 보호. 잠시 쉬어도 괜찮아요"},{t:"<strong>달팽이 흔적</strong> → 지나온 흔적을 남기는 과정"}]},{e:"🦂",n:"전갈/독충",cat:"동물",tags:["주의"],meaning:"독이 있는 생물은 위험, 배신, 치명적 매력의 상징.",contexts:[{t:"<strong>전갈에 쏘인다</strong> → 가까운 사람에게 상처받을 수 있어요"},{t:"<strong>독충이 기어다닌다</strong> → 주변에 소소한 위험 요소"},{t:"<strong>독을 피한다</strong> → 위기를 잘 피해가고 있어요"}]},{e:"🐬",n:"물개/바다생물",cat:"동물",tags:["길몽"],meaning:"바다 동물은 감정의 세계, 무의식 탐험의 가이드.",contexts:[{t:"<strong>물개가 재롱을 부린다</strong> → 즐거움과 유머. 가볍게 살아도 돼요"},{t:"<strong>해파리</strong> → 아름답지만 주의 필요. 겉모습에 속지 마세요"},{t:"<strong>불가사리</strong> → 재생 능력. 상처에서 회복하는 힘"},{t:"<strong>문어</strong> → 다재다능. 여러 일을 동시에 처리하는 능력"}]},{e:"🐓",n:"닭/오리",cat:"동물",tags:["길몽"],meaning:"가금류는 소박한 풍요, 일상의 행운, 알(잠재력)의 상징.",contexts:[{t:"<strong>닭이 운다</strong> → 새벽을 알리는 신호. 새 시작"},{t:"<strong>오리가 물에서 헤엄친다</strong> → 감정 위를 유유히 다니는 평화"},{t:"<strong>병아리</strong> → 귀엽고 작은 새 시작. 보호가 필요"},{t:"<strong>황금 닭</strong> → 재물 길몽. 작은 투자가 큰 결실"}]},{e:"🐑",n:"양/목장",cat:"동물",tags:["길몽"],meaning:"양은 순수함, 평화, 공동체의 상징.",contexts:[{t:"<strong>양 떼를 본다</strong> → 평화로운 시기. 안정적인 공동체"},{t:"<strong>양털을 깎는다</strong> → 수확의 시기. 노력의 결실을 거둬요"},{t:"<strong>어린 양</strong> → 순수함과 새 시작"},{t:"<strong>목장에 있다</strong> → 풍요롭고 안정적인 생활"}]},{e:"🏗️",n:"공사장/건설",cat:"장소",tags:["중립"],meaning:"공사는 인생의 건설, 변화 진행 중, 미완성 상태.",contexts:[{t:"<strong>집을 짓고 있다</strong> → 인생을 새로 설계하는 과정"},{t:"<strong>공사 소음</strong> → 변화가 진행 중. 시끄럽지만 필요한 과정"},{t:"<strong>완공된 건물</strong> → 노력의 결실. 새 단계 시작"},{t:"<strong>철거 현장</strong> → 과거를 허물고 새로 시작하는 과정"}]},{e:"🚢",n:"배/항구",cat:"장소",tags:["중립"],meaning:"배는 감정의 바다를 건너는 여정, 항구는 안식처.",contexts:[{t:"<strong>큰 배를 탄다</strong> → 안정적인 여정. 큰 프로젝트의 시작"},{t:"<strong>작은 보트</strong> → 혼자서 감정을 다루는 과정"},{t:"<strong>항구에 도착한다</strong> → 목표에 다다르거나 안식을 찾는 시기"},{t:"<strong>폭풍 속 배</strong> → 감정의 풍파를 겪고 있어요"},{t:"<strong>배가 침몰한다</strong> → 계획이 무너지는 두려움. 하지만 재기 가능"}]},{e:"🏫",n:"도서관/서점",cat:"장소",tags:["길몽"],meaning:"지식의 공간은 배움, 발견, 지혜의 상징.",contexts:[{t:"<strong>도서관에서 책을 읽는다</strong> → 답을 찾고 있어요. 곧 발견할 거예요"},{t:"<strong>서점에서 책을 고른다</strong> → 인생의 방향을 선택하는 과정"},{t:"<strong>책이 끝없이 있다</strong> → 무한한 가능성과 지식"}]},{e:"🏖️",n:"수영장/워터파크",cat:"장소",tags:["중립"],meaning:"인공적인 물 공간은 통제된 감정 경험의 상징.",contexts:[{t:"<strong>수영장에서 논다</strong> → 감정을 안전하게 다루는 과정"},{t:"<strong>다이빙한다</strong> → 깊은 감정 속으로 뛰어드는 용기"},{t:"<strong>물이 차갑다</strong> → 예상과 다른 감정적 충격"},{t:"<strong>미끄럼틀을 탄다</strong> → 즐거운 감정의 흐름"}]},{e:"🌉",n:"다리/터널",cat:"장소",tags:["중립"],meaning:"다리와 터널은 전환, 통과의례, 과도기의 상징.",contexts:[{t:"<strong>긴 터널을 지나간다</strong> → 힘든 시기를 통과하는 중. 끝이 보여요"},{t:"<strong>터널 끝에 빛</strong> → 희망! 어려움이 끝나가요"},{t:"<strong>현수교를 건넌다</strong> → 불안하지만 나아가야 해요"},{t:"<strong>다리가 무너진다</strong> → 연결이 끊어지는 느낌"}]},{e:"🗻",n:"절벽/깊은 곳",cat:"장소",tags:["주의"],meaning:"절벽은 위기, 결단, 극적 변화의 상징.",contexts:[{t:"<strong>절벽 끝에 서 있다</strong> → 중대한 결정 앞에 있어요"},{t:"<strong>절벽에서 뛰어내린다</strong> → 모험적 결단. 도약의 용기"},{t:"<strong>깊은 구덩이</strong> → 우울하거나 함정에 빠진 느낌"},{t:"<strong>협곡을 내려다본다</strong> → 두렵지만 아름다운 가능성"}]},{e:"🏘️",n:"마을/도시",cat:"장소",tags:["중립"],meaning:"마을은 공동체, 도시는 사회적 야망의 상징.",contexts:[{t:"<strong>시골 마을에 있다</strong> → 단순함과 평화에 대한 갈망"},{t:"<strong>대도시를 걷는다</strong> → 야망과 기회. 바쁜 일상"},{t:"<strong>빈 도시/폐허 도시</strong> → 고립감이나 무너진 사회적 관계"},{t:"<strong>고향에 돌아간다</strong> → 뿌리를 찾고 싶은 마음"}]},{e:"🎮",n:"게임/놀이",cat:"행동",tags:["중립"],meaning:"게임은 경쟁, 전략, 현실 도피의 상징.",contexts:[{t:"<strong>게임에서 이긴다</strong> → 현실에서도 성취감을 느낄 거예요"},{t:"<strong>게임에서 진다</strong> → 좌절이지만 다시 도전할 수 있어요"},{t:"<strong>게임 속에 갇힌다</strong> → 현실과 가상의 경계가 흐려진 상태"},{t:"<strong>보드게임을 한다</strong> → 전략적 사고가 필요한 시기"}]},{e:"🎣",n:"낚시",cat:"행동",tags:["길몽"],meaning:"낚시는 인내, 기다림, 기회 포착의 상징.",contexts:[{t:"<strong>큰 물고기를 잡았다</strong> → 대길! 큰 기회를 잡았어요"},{t:"<strong>아무것도 안 잡힌다</strong> → 아직 때가 아니에요. 인내 필요"},{t:"<strong>미끼를 던진다</strong> → 기회를 위해 준비하고 있어요"},{t:"<strong>낚싯줄이 끊어진다</strong> → 아깝지만 더 큰 기회가 올 수 있어요"}]},{e:"📸",n:"촬영/영상",cat:"행동",tags:["중립"],meaning:"촬영은 기록, 관찰자 시점, 기억 보존의 상징.",contexts:[{t:"<strong>사진을 찍힌다</strong> → 주목받고 있어요. 좋든 싫든"},{t:"<strong>영상을 찍는다</strong> → 이 경험을 기록하고 싶은 마음"},{t:"<strong>과거 영상을 본다</strong> → 추억에 대한 그리움"}]},{e:"💃",n:"파티/축제",cat:"행동",tags:["길몽"],meaning:"축제는 기쁨, 사교, 축하의 상징.",contexts:[{t:"<strong>파티에서 즐긴다</strong> → 사교적 에너지. 좋은 만남"},{t:"<strong>깜짝 파티</strong> → 예상치 못한 기쁜 일이 생겨요"},{t:"<strong>혼자 파티에 있다</strong> → 외로움. 소속감에 대한 갈망"},{t:"<strong>축제 행렬</strong> → 성대한 변화의 시작"}]},{e:"🏋️",n:"훈련/수련",cat:"행동",tags:["중립"],meaning:"훈련은 자기 단련, 준비, 역경 극복의 상징.",contexts:[{t:"<strong>운동을 열심히 한다</strong> → 목표를 위해 자기를 다듬는 중"},{t:"<strong>무술을 배운다</strong> → 자기 방어와 강인함을 키우는 과정"},{t:"<strong>명상/요가</strong> → 내면의 평화를 찾는 시기"},{t:"<strong>마라톤을 뛴다</strong> → 긴 호흡이 필요해요. 포기하지 마세요"}]},{e:"🧳",n:"이사/짐싸기",cat:"행동",tags:["중립"],meaning:"이사는 변화, 새 환경, 과거와의 이별.",contexts:[{t:"<strong>이사를 한다</strong> → 인생의 새 단계. 환경 변화"},{t:"<strong>짐을 싸는 중</strong> → 변화를 준비하고 있어요"},{t:"<strong>짐이 너무 많다</strong> → 과거의 짐이 무거워요. 정리가 필요"},{t:"<strong>빈 방에 도착한다</strong> → 새로운 가능성. 아직 채워지지 않은 미래"}]},{e:"🤲",n:"기도/간절함",cat:"행동",tags:["중립"],meaning:"기도는 간절한 소원, 초월적 도움 요청, 겸손의 상징.",contexts:[{t:"<strong>기도를 한다</strong> → 간절한 마음이 있어요. 진심은 통해요"},{t:"<strong>소원을 빈다</strong> → 꿈을 향한 의지. 방향은 맞아요"},{t:"<strong>다른 사람을 위해 기도한다</strong> → 이타심. 남을 생각하는 마음"}]},{e:"🍦",n:"아이스크림/디저트",cat:"음식",tags:["길몽"],meaning:"디저트는 보상, 달콤한 즐거움, 자기 관리의 상징.",contexts:[{t:"<strong>아이스크림을 먹는다</strong> → 자기에게 선물. 여유를 즐길 때"},{t:"<strong>아이스크림이 녹는다</strong> → 좋은 시간은 빠르게 지나가요. 지금을 즐기세요"},{t:"<strong>초콜릿을 먹는다</strong> → 사랑이나 위로. 달콤한 순간"},{t:"<strong>달콤한 것이 입에 가득</strong> → 행복한 시기가 다가오고 있어요"}]},{e:"🌶️",n:"매운 음식/자극적인 것",cat:"음식",tags:["중립"],meaning:"매운 음식은 자극, 열정, 도전의 상징.",contexts:[{t:"<strong>매운 것을 먹는다</strong> → 자극적인 경험을 원하는 마음"},{t:"<strong>매워서 울다</strong> → 감정이 격해지는 상황"},{t:"<strong>향신료</strong> → 일상에 변화를 주고 싶은 욕구"}]},{e:"🍵",n:"약/한약",cat:"음식",tags:["중립"],meaning:"약은 치유, 씁쓸한 현실, 필요한 처방의 상징.",contexts:[{t:"<strong>약을 먹는다</strong> → 치유 과정. 지금은 쓰지만 나아질 거예요"},{t:"<strong>한약을 달인다</strong> → 정성스러운 회복 과정. 시간이 걸려요"},{t:"<strong>약을 거부한다</strong> → 변화나 치유를 받아들이기 어려운 상태"}]},{e:"🍶",n:"물/음료",cat:"음식",tags:["중립"],meaning:"마시는 물은 정화, 생명력, 갈증(욕구)의 상징.",contexts:[{t:"<strong>맑은 물을 마신다</strong> → 정화와 재충전. 건강운 상승"},{t:"<strong>목이 말라 물을 찾는다</strong> → 채워지지 않은 욕구가 있어요"},{t:"<strong>탁한 물을 마신다</strong> → 좋지 않은 정보나 영향에 노출"},{t:"<strong>샘물을 발견한다</strong> → 근원적 치유. 진정한 해답을 찾아요"}]},{e:"🧞",n:"소원/요정",cat:"초자연",tags:["길몽"],meaning:"소원을 들어주는 존재는 간절한 바람, 기적의 가능성.",contexts:[{t:"<strong>지니가 나타났다</strong> → 소원이 이뤄질 수 있는 시기"},{t:"<strong>요정을 만난다</strong> → 작은 기적이나 행운"},{t:"<strong>소원이 이뤄진다</strong> → 강한 의지가 현실을 만들어요"},{t:"<strong>소원을 고르지 못한다</strong> → 진짜 원하는 게 뭔지 모르겠는 상태"}]},{e:"🌀",n:"시간여행/반복",cat:"초자연",tags:["중립"],meaning:"시간 관련 꿈은 후회, 기회, 삶의 순환의 상징.",contexts:[{t:"<strong>과거로 돌아간다</strong> → 후회나 그리움. 지나간 것에 대한 미련"},{t:"<strong>미래를 본다</strong> → 불안하거나 기대에 찬 상태"},{t:"<strong>같은 하루가 반복된다</strong> → 일상의 반복에 갇힌 느낌"},{t:"<strong>시간이 멈춘다</strong> → 쉼이 필요해요. 잠시 멈춰도 괜찮아요"}]},{e:"💫",n:"환생/전생",cat:"초자연",tags:["중립"],meaning:"전생 꿈은 깊은 자아 탐색, 운명적 인연의 상징.",contexts:[{t:"<strong>전생의 모습을 본다</strong> → 현재 성격의 뿌리를 이해하는 과정"},{t:"<strong>다른 시대에 있다</strong> → 현재와 다른 삶에 대한 갈망"},{t:"<strong>운명적 만남</strong> → 설명 안 되는 강한 끌림. 영혼의 연결"}]},{e:"🧠",n:"뇌/생각",cat:"신체",tags:["중립"],meaning:"뇌는 사고력, 결정, 정보 처리의 상징.",contexts:[{t:"<strong>머리가 아프다</strong> → 생각이 너무 많아요. 과부하 상태"},{t:"<strong>머리가 맑아진다</strong> → 깨달음의 순간. 답이 보여요"},{t:"<strong>뇌가 보인다</strong> → 자기 사고 패턴을 객관적으로 보는 시기"},{t:"<strong>기억이 안 난다</strong> → 무의식이 보호하려고 숨기는 기억"}]},{e:"💪",n:"근육/힘",cat:"신체",tags:["중립"],meaning:"근육은 힘, 능력, 자신감의 상징.",contexts:[{t:"<strong>힘이 세졌다</strong> → 자신감 상승. 능력이 커지는 시기"},{t:"<strong>힘이 빠진다</strong> → 무력감. 에너지 충전이 필요해요"},{t:"<strong>무거운 것을 든다</strong> → 책임감을 감당하는 과정"},{t:"<strong>날씬해졌다/뚱뚱해졌다</strong> → 자기 이미지에 대한 의식"}]},{e:"🦷",n:"혀/목소리",cat:"신체",tags:["중립"],meaning:"목소리는 자기 표현, 주장, 진실의 상징.",contexts:[{t:"<strong>큰 소리로 외친다</strong> → 표현되지 못한 것을 내보내야 해요"},{t:"<strong>속삭인다</strong> → 비밀이나 조심스러운 감정"},{t:"<strong>목소리가 변한다</strong> → 정체성의 변화. 새로운 표현 방식"},{t:"<strong>다른 사람의 목소리로 말한다</strong> → 그 사람의 역할을 수행하고 있어요"}]},{e:"👶",n:"쌍둥이/분신",cat:"사람",tags:["중립"],meaning:"분신은 자아의 다른 면, 선택의 갈림길, 갈등.",contexts:[{t:"<strong>나의 분신을 만난다</strong> → 자기 안의 다른 면과 마주하는 과정"},{t:"<strong>쌍둥이가 태어난다</strong> → 두 가지 가능성이 동시에"},{t:"<strong>도플갱어</strong> → 정체성 불안. 진짜 나는 누구인가"},{t:"<strong>거울 속 다른 나</strong> → 숨기고 있던 자아와의 만남"}]},{e:"👸",n:"왕/여왕",cat:"사람",tags:["길몽"],meaning:"왕족은 권위, 리더십, 자기 가치의 상징.",contexts:[{t:"<strong>왕이 된다</strong> → 리더십을 발휘할 시기"},{t:"<strong>여왕을 만난다</strong> → 강한 여성 에너지. 내면의 힘"},{t:"<strong>왕관을 쓴다</strong> → 인정과 성취. 자부심"},{t:"<strong>왕좌에서 내려온다</strong> → 겸손이 필요한 시기"}]},{e:"🧒",n:"낯선 아이",cat:"사람",tags:["중립"],meaning:"모르는 아이는 내면의 어린 자아, 잠재력, 순수함.",contexts:[{t:"<strong>낯선 아이가 울고 있다</strong> → 내면의 상처받은 아이가 위로를 원해요"},{t:"<strong>아이가 나를 부른다</strong> → 잊고 있던 순수한 마음"},{t:"<strong>아이를 보호한다</strong> → 자기 안의 연약한 부분을 돌보는 과정"},{t:"<strong>아이가 웃으며 달려온다</strong> → 기쁨과 희망. 좋은 일이 와요"}]},{e:"👻",n:"그림자 인물",cat:"사람",tags:["중립"],meaning:"얼굴 없는 사람, 실루엣은 미지의 자아나 가능성.",contexts:[{t:"<strong>얼굴 없는 사람이 서 있다</strong> → 아직 결정하지 못한 미래"},{t:"<strong>그림자가 따라온다</strong> → 인정하지 않은 자기 모습"},{t:"<strong>실루엣이 사라진다</strong> → 기회가 지나가고 있어요"},{t:"<strong>어둠 속 누군가</strong> → 아직 만나지 못한 중요한 인연"}]}];export{t as E};
